{
  "name": "SistemCaja",
  "description": "Plataforma administrativa integral con gestión de ventas, inventario, compras y lanzador de aplicaciones externas. Incluye asistente IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  name: string;
  price: number;
  stock: number;
  sku: string;
  category: string;
}

export interface Sale {
  id: string;
  date: string; // ISO string
  items: { productId: string; quantity: number; priceAtSale: number; name: string }[];
  total: number;
  paymentMethod: 'cash' | 'card' | 'transfer';
}

export interface Purchase {
  id: string;
  date: string;
  supplier: string;
  items: { productId: string; quantity: number; cost: number; name: string }[];
  total: number;
}

export interface Return {
  id: string;
  saleId: string;
  date: string;
  reason: string;
  status: 'pending' | 'approved' | 'rejected';
}

export interface ExternalApp {
  id: string;
  name: string;
  url: string;
  description: string;
  iconName: string; // Representing icon name
}

export type ViewState = 'dashboard' | 'sales' | 'purchases' | 'returns' | 'inventory' | 'apps';

import { GoogleGenAI, Chat } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Initialize the client only if the key exists, but handle missing key gracefully in calls
const ai = new GoogleGenAI({ apiKey });

export const createChatSession = (): Chat => {
  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `Eres "CajaBot", un asistente inteligente experto en gestión administrativa y soporte técnico para la plataforma "SistemCaja".

      Tus funciones son:
      1. Ayudar a los usuarios a navegar por la aplicación (Ventas, Compras, Inventario, Devoluciones, Panel).
      2. Explicar conceptos contables básicos (Ticket promedio, ROI, margen de ganancia).
      3. Analizar datos si el usuario te los proporciona en texto.
      4. Ser amable, profesional y conciso.

      La aplicación tiene las siguientes secciones:
      - Dashboard: Métricas clave y gráficos.
      - Ventas: Registrar nuevas ventas.
      - Compras: Registrar ingresos de mercadería.
      - Inventario: Ver y editar stock.
      - Devoluciones: Gestión de garantías.
      - Aplicaciones: Un lanzador para herramientas externas.

      Responde siempre en español.`,
      thinkingConfig: { thinkingBudget: 1024 } // Enable thinking for better reasoning on business questions
    },
  });
};

export const sendMessageToGemini = async (chat: Chat, message: string) => {
  try {
    const result = await chat.sendMessageStream({ message });
    return result;
  } catch (error) {
    console.error("Error sending message to Gemini:", error);
    throw error;
  }
};

import React, { useMemo } from 'react';
import { Sale } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';
import { DollarSign, ShoppingBag, TrendingUp, AlertCircle } from 'lucide-react';

interface DashboardProps {
  sales: Sale[];
}

const Dashboard: React.FC<DashboardProps> = ({ sales }) => {

  const stats = useMemo(() => {
    const totalRevenue = sales.reduce((acc, sale) => acc + sale.total, 0);
    const totalTransactions = sales.length;
    const avgTicket = totalTransactions > 0 ? totalRevenue / totalTransactions : 0;

    // Monthly sales data for chart
    const salesByMonth = sales.reduce((acc, sale) => {
      const month = new Date(sale.date).toLocaleString('es-ES', { month: 'short' });
      acc[month] = (acc[month] || 0) + sale.total;
      return acc;
    }, {} as Record<string, number>);

    const chartData = Object.keys(salesByMonth).map(month => ({
      name: month,
      ventas: salesByMonth[month]
    }));

    // Find best sellers
    const productSales: Record<string, number> = {};
    sales.forEach(sale => {
        sale.items.forEach(item => {
            productSales[item.name] = (productSales[item.name] || 0) + item.quantity;
        });
    });

    const topProducts = Object.entries(productSales)
        .sort(([, a], [, b]) => b - a)
        .slice(0, 5)
        .map(([name, quantity]) => ({ name, quantity }));

    return { totalRevenue, totalTransactions, avgTicket, chartData, topProducts };
  }, [sales]);

  const StatCard = ({ title, value, icon: Icon, color }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between">
      <div>
        <p className="text-sm font-medium text-gray-500 mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-gray-800">{value}</h3>
      </div>
      <div className={`p-3 rounded-full ${color} bg-opacity-10`}>
        <Icon className={`w-6 h-6 ${color.replace('bg-', 'text-')}`} />
      </div>
    </div>
  );

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Panel de Control</h2>
        <span className="text-sm text-gray-500">Última actualización: Ahora</span>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
            title="Ventas Totales" 
            value={`$${stats.totalRevenue.toLocaleString()}`} 
            icon={DollarSign} 
            color="bg-green-500" 
        />
        <StatCard 
            title="Transacciones" 
            value={stats.totalTransactions} 
            icon={ShoppingBag} 
            color="bg-blue-500" 
        />
        <StatCard 
            title="Ticket Promedio" 
            value={`$${stats.avgTicket.toFixed(2)}`} 
            icon={TrendingUp} 
            color="bg-purple-500" 
        />
        <StatCard 
            title="Productos Top" 
            value={stats.topProducts.length} 
            icon={AlertCircle} 
            color="bg-orange-500" 
        />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-6">
        {/* Sales Trend */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">Tendencia de Ventas (Mensual)</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b'}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b'}} />
                <Tooltip 
                    cursor={{fill: '#f1f5f9'}}
                    contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="ventas" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Top Products */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">Lo Más Vendido</h3>
          <div className="h-64">
             <ResponsiveContainer width="100%" height="100%">
                <LineChart data={stats.topProducts} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                    <XAxis type="number" hide />
                    <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                    <Tooltip />
                    <Line type="monotone" dataKey="quantity" stroke="#8884d8" strokeWidth={2} dot={{r: 4}} />
                </LineChart>
            </ResponsiveContainer>
             <ul className="mt-4 space-y-2">
                {stats.topProducts.map((p, idx) => (
                    <li key={idx} className="flex justify-between text-sm text-gray-600 border-b pb-1 last:border-0">
                        <span>{idx + 1}. {p.name}</span>
                        <span className="font-semibold">{p.quantity} un.</span>
                    </li>
                ))}
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { ExternalApp } from '../types';
import { ExternalLink, Plus, Trash2, Globe, Calculator, Mail, Layout } from 'lucide-react';

interface AppLauncherProps {
  apps: ExternalApp[];
  onAddApp: (app: ExternalApp) => void;
  onRemoveApp: (id: string) => void;
}

