// --- Sales Register Component ---
const SalesView = ({ products, onSale }: { products: Product[], onSale: (sale: Sale) => void }) => {
    const [cart, setCart] = useState<{product: Product, qty: number}[]>([]);

    const addToCart = (productId: string) => {
        const prod = products.find(p => p.id === productId);
        if (!prod) return;
        const existing = cart.find(i => i.product.id === productId);
        if (existing) {
            setCart(cart.map(i => i.product.id === productId ? {...i, qty: i.qty + 1} : i));
        } else {
            setCart([...cart, {product: prod, qty: 1}]);
        }
    };

    const total = cart.reduce((acc, item) => acc + (item.product.price * item.qty), 0);

    const handleCheckout = () => {
        if (cart.length === 0) return;
        const sale: Sale = {
            id: Date.now().toString(),
            date: new Date().toISOString(),
            items: cart.map(i => ({
                productId: i.product.id,
                name: i.product.name,
                quantity: i.qty,
                priceAtSale: i.product.price
            })),
            total: total,
            paymentMethod: 'cash'
        };
        onSale(sale);
        setCart([]);
        alert('Venta registrada con éxito');
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-8rem)]">
