    *   Descripción: "v1".
    *   Ejecutar como: **"Yo"** (tu cuenta).
    *   Quién tiene acceso: **"Cualquier persona"** (Anyone). *Esto es necesario para que tu app de React pueda acceder sin login complejo de Google.*
    *   Copia la **URL de la aplicación web** generada (termina en `/exec`).

**Código para Google Apps Script:**

```javascript
function setup() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheets = [
    { name: 'Products', headers: ['id', 'name', 'price', 'stock', 'sku', 'category'] },
    { name: 'Sales', headers: ['id', 'date', 'items', 'total', 'paymentMethod', 'customerId', 'customerName'] },
    { name: 'Customers', headers: ['id', 'name', 'email', 'phone', 'address'] },
    { name: 'Users', headers: ['id', 'name', 'username', 'role', 'password'] },
    { name: 'Apps', headers: ['id', 'name', 'url', 'description', 'iconName'] }
  ];

  sheets.forEach(conf => {
    let sheet = ss.getSheetByName(conf.name);
    if (!sheet) {
      sheet = ss.insertSheet(conf.name);
      sheet.appendRow(conf.headers);
    }
  });
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const data = {};

  ['Products', 'Sales', 'Customers', 'Users', 'Apps'].forEach(name => {
    const sheet = ss.getSheetByName(name);
    const rows = sheet.getDataRange().getValues();
    const headers = rows.shift();
    data[name.toLowerCase()] = rows.map(row => {
      let obj = {};
      headers.forEach((h, i) => {
        // Parsear JSON para la columna items de ventas
        if(h === 'items' && row[i]) {
          try { obj[h] = JSON.parse(row[i]); } catch(e) { obj[h] = []; }
        } else {
          obj[h] = row[i];
        }
      });
      return obj;
    });
  });

  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const body = JSON.parse(e.postData.contents);
  const action = body.action;
  const sheetName = body.sheet;
  const data = body.data;

  const sheet = ss.getSheetByName(sheetName);

  if (action === 'create') {
    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
    const row = headers.map(h => {
      if (h === 'items') return JSON.stringify(data[h]);
      return data[h] || '';
    });
    sheet.appendRow(row);
    return response({ status: 'success', id: data.id });
  }

  if (action === 'updateStock') {
    // Optimizado para actualizar stock basado en ID
    const rows = sheet.getDataRange().getValues();
    const idIndex = 0; // Asumiendo ID en col 0
    const stockIndex = 3; // Asumiendo stock en col 3

    for (let i = 1; i < rows.length; i++) {
      if (rows[i][idIndex] == data.id) {
        sheet.getRange(i + 1, stockIndex + 1).setValue(data.stock);
        return response({ status: 'updated' });
      }
    }
  }

  // Lógica simple de borrado para Apps
  if (action === 'delete') {
      const rows = sheet.getDataRange().getValues();
      for (let i = 1; i < rows.length; i++) {
        if (rows[i][0] == data.id) {
            sheet.deleteRow(i + 1);
            return response({ status: 'deleted' });
        }
      }
  }

  return response({ status: 'error', message: 'Action not found' });
}

function response(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}
```

### PASO 2: Actualización de la Aplicación (React)

He creado un servicio `api.ts` para comunicar con Sheets y he actualizado `App.tsx` para usar estos datos reales en lugar de los datos de prueba.

**IMPORTANTE:** Debes pegar la URL que obtuviste en el paso anterior en la variable `SHEETS_API_URL` dentro del archivo `services/api.ts` (te indicaré dónde en el código).

