import { Product, Sale, Customer, User, ExternalApp } from '../types';

// ¡IMPORTANTE! Reemplaza esta URL con la que obtuviste al desplegar tu Google Apps Script
// Ejemplo: https://script.google.com/macros/s/AKfycbx.../exec
const SHEETS_API_URL = 'https://script.google.com/macros/s/AKfycbx.../exec'; 

// Si el usuario no ha puesto la URL, usamos un modo mock para que no falle la UI
const isConfigured = SHEETS_API_URL.includes('AKfycbx'); 

export interface AppData {
  products: Product[];
  sales: Sale[];
  customers: Customer[];
  users: User[];
  apps: ExternalApp[];
}

export const fetchAllData = async (): Promise<AppData> => {
  if (!isConfigured) {
    console.warn("API URL not configured. Returning empty data.");
    return { products: [], sales: [], customers: [], users: [], apps: [] };
  }

  try {
    const response = await fetch(SHEETS_API_URL);
    const data = await response.json();
    return {
      products: data.products || [],
      sales: data.sales || [],
      customers: data.customers || [],
      users: data.users || [],
      apps: data.apps || []
    };
  } catch (error) {
    console.error("Error fetching data:", error);
    throw error;
  }
};

const sendRequest = async (action: string, sheet: string, data: any) => {
  if (!isConfigured) return; // Silent fail in mock mode

  // Google Apps Script requires 'no-cors' for simple POSTs sometimes, 
  // but 'text/plain' body avoids preflight issues usually.
  try {
    await fetch(SHEETS_API_URL, {
      method: 'POST',
      body: JSON.stringify({ action, sheet, data }),
      // Important: Using text/plain prevents CORS preflight OPTIONS request
      // which Google Apps Script doesn't handle natively without complex headers
      headers: { "Content-Type": "text/plain;charset=utf-8" }, 
    });
  } catch (error) {
    console.error(`Error executing ${action} on ${sheet}:`, error);
  }
};

