                quantity: i.qty,
                priceAtSale: i.product.price
            })),
            total: total,
            paymentMethod: 'cash',
            customerId: customer?.id,
            customerName: customer?.name
        };
        onSale(sale);
        setCart([]);
        setSelectedCustomerId('');
    };

    return (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-8rem)]">
