                                <Package size={24} />
                            </div>
                            <h3 className="font-semibold text-gray-800 text-sm line-clamp-2">{p.name}</h3>
                            <p className="text-blue-600 font-bold mt-1">${p.price}</p>
                            <p className={`text-xs mt-2 ${p.stock === 0 ? 'text-red-500 font-bold' : 'text-gray-400'}`}>Stock: {p.stock}</p>
                        </div>
                    ))}
                </div>
            </div>

            {/* Cart / Checkout */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6 flex flex-col">
                <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                    <ShoppingCart size={20} />
