                        <p className="text-gray-400 text-center py-10">El carrito está vacío</p>
                    ) : cart.map((item, idx) => (
                        <div key={idx} className="flex justify-between items-center text-sm border-b border-gray-50 pb-2">
                            <div>
                                <p className="font-medium text-gray-800">{item.product.name}</p>
                                <p className="text-gray-500 text-xs">{item.qty} x ${item.product.price}</p>
