                          </thead>
                          <tbody className="divide-y divide-gray-100">
                              {auditData.map((item) => (
                                  <tr key={item.sku} className={`
                                      ${item.status === 'matched' ? 'bg-white' : ''}
                                      ${item.status === 'missing' ? 'bg-red-50' : ''}
                                      ${item.status === 'surplus' ? 'bg-yellow-50' : ''}
