Sí, es necesario actualizar el **Google Apps Script** para que soporte la nueva estructura de **Compras**, la actualización automática de **Clientes** y la estructura específica que pediste para el **Inventario**.

Aquí tienes el código completo para tu archivo `Code.gs` en el editor de Google Apps Script.

### Instrucciones de instalación:
1. Ve a tu proyecto en Google Apps Script.
2. Borra todo el código que tengas en `Code.gs`.
3. Pega el siguiente código.
4. **IMPORTANTE:** Ejecuta la función `setup()` una vez desde el editor para que se creen las hojas con las columnas nuevas automáticamente (Compras, Clientes, etc.).
5. Vuelve a hacer un **"Nueva implementación"** (New Deployment) -> Selecciona "Aplicación web" -> En "Quién tiene acceso" selecciona **"Cualquiera"** -> Copia la **nueva URL**.
6. Actualiza la variable `SHEETS_API_URL` en tu archivo `services/api.ts` con la nueva URL.

### Código Google Apps Script (`Code.gs`)

```javascript
/**
 * SISTEMCAJA - BACKEND (Google Apps Script)
 * Maneja Inventario, Ventas, Compras, Clientes, Usuarios y Apps.
 */

function doGet() {
  const data = {
    products: getSheetData('Inventario'),
    sales: getSheetData('Ventas'),
    purchases: getSheetData('Compras'),
    customers: getSheetData('Clientes'),
    users: getSheetData('Usuarios'),
    apps: getSheetData('Apps')
  };

  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const request = JSON.parse(e.postData.contents);
  const action = request.action;
  const sheetName = mapSheetName(request.sheet);
  const data = request.data;

  let result = { status: 'success' };

  const lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    if (action === 'create') {
      createRecord(sheetName, data);

      // Si es una Compra, aumentar el stock automáticamente
      if (sheetName === 'Compras') {
        updateStockFromPurchase(data);
      }
    } 
    else if (action === 'updateStock') {
      updateStock(data.id, data.stock);
    }
    else if (action === 'delete') {
      deleteRecord(sheetName, data.id);
    }

  } catch (err) {
    result = { status: 'error', message: err.toString() };
  } finally {
    lock.releaseLock();
  }

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

// --- FUNCIONES PRINCIPALES ---

function createRecord(sheetName, data) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName(sheetName);
  if (!sheet) throw new Error("Hoja no encontrada: " + sheetName);

  const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const row = [];

  headers.forEach(header => {
    // Mapeo especial para objetos complejos que se guardan como JSON string
    if (header === 'Items' || header === 'items') {
      row.push(JSON.stringify(data.items || []));
    } else {
      // Intenta encontrar la propiedad coincidente en minúsculas o camelCase
      const key = Object.keys(data).find(k => k.toLowerCase() === header.toLowerCase());
      row.push(key ? data[key] : '');
    }
  });

  sheet.appendRow(row);
}

function updateStock(id, newStock) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('Inventario');
  const data = sheet.getDataRange().getValues();

  // Asumimos que la columna 0 es ID
  for (let i = 1; i < data.length; i++) {
    if (String(data[i][0]) === String(id)) {
      // Asumimos que la columna "Stock" es la columna index 5 (F) basada en la estructura setup()
      // Buscamos dinámicamente la columna 'Stock'
      const headerRow = data[0];
      const stockIndex = headerRow.indexOf('Stock');
      if (stockIndex > -1) {
        sheet.getRange(i + 1, stockIndex + 1).setValue(newStock);
      }
      break;
    }
  }
}

function updateStockFromPurchase(purchaseData) {
  const sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('Inventario');
  const data = sheet.getDataRange().getValues();
  const headers = data[0];
  const idIndex = headers.indexOf('ID');
  const stockIndex = headers.indexOf('Stock');

  if (idIndex === -1 || stockIndex === -1) return;

  const items = purchaseData.items || [];

  // Recorremos los items comprados
  items.forEach(item => {
    // Buscamos el producto en el inventario por ID (o podrías cambiar lógica para buscar por IMEI/SKU)
    for (let i = 1; i < data.length; i++) {
      if (String(data[i][idIndex]) === String(item.productId)) {
        const currentStock = Number(data[i][stockIndex]) || 0;
        const newStock = currentStock + Number(item.quantity);
        sheet.getRange(i + 1, stockIndex + 1).setValue(newStock);
