// Helper para calcular fechas de pago (15 y 30)
const calculatePaymentDates = (startDate: Date, installments: number) => {
    const dates: string[] = [];
    let current = new Date(startDate);

    // Avanzamos al primer hito de cobro cercano
    // Si es antes del 15, el primer cobro es el 15.
    // Si es entre 15 y 30, el primer cobro es el 30.
    // Si es 30 o 31, el primer cobro es el 15 del mes siguiente.

    if (current.getDate() < 15) {
        current.setDate(15);
    } else if (current.getDate() < 30) {
        // Intentar fijar a 30, si es febrero maneja el desbordamiento js nativo
        current.setDate(30); 
    } else {
        // Mes siguiente día 15
        current.setMonth(current.getMonth() + 1);
        current.setDate(15);
    }

    for (let i = 0; i < installments; i++) {
        // Ajuste para meses que no tienen día 30 (Febrero)
        // Si nos pasamos de mes al poner día 30, retrocedemos al último día del mes anterior
        const y = current.getFullYear();
        const m = current.getMonth();
        const d = current.getDate();

        // Validación básica de fin de mes
        if (d > 28) {
             const lastDay = new Date(y, m + 1, 0).getDate();
             if (d > lastDay) current.setDate(lastDay);
        }

        dates.push(current.toLocaleDateString('es-ES'));

        // Calcular siguiente fecha
        if (current.getDate() <= 15) {
            // Del 15 saltamos al 30 (o fin de mes)
            const lastDayOfMonth = new Date(current.getFullYear(), current.getMonth() + 1, 0).getDate();
            current.setDate(lastDayOfMonth >= 30 ? 30 : lastDayOfMonth); 
        } else {
            // Del 30 saltamos al 15 del siguiente mes
            current.setMonth(current.getMonth() + 1);
            current.setDate(15);
        }
    }
    return dates;
};

