// Helper para calcular fechas de pago (15 y 30)
const calculatePaymentDates = (startDate: Date, installments: number) => {
    const dates: string[] = [];
    let current = new Date(startDate);

    if (current.getDate() < 15) {
        current.setDate(15);
    } else if (current.getDate() < 30) {
        current.setDate(30); 
    } else {
        current.setMonth(current.getMonth() + 1);
        current.setDate(15);
    }

    for (let i = 0; i < installments; i++) {
        const y = current.getFullYear();
        const m = current.getMonth();
        const d = current.getDate();

        if (d > 28) {
             const lastDay = new Date(y, m + 1, 0).getDate();
             if (d > lastDay) current.setDate(lastDay);
        }

        dates.push(current.toLocaleDateString('es-ES'));

        if (current.getDate() <= 15) {
            const lastDayOfMonth = new Date(current.getFullYear(), current.getMonth() + 1, 0).getDate();
            current.setDate(lastDayOfMonth >= 30 ? 30 : lastDayOfMonth); 
        } else {
            current.setMonth(current.getMonth() + 1);
            current.setDate(15);
        }
    }
    return dates;
};

const SalesView: React.FC<SalesViewProps> = ({ products, customers, onSale }) => {
    // Estado Global de Venta
    const [cart, setCart] = useState<{product: Product, qty: number}[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedCustomer, setSelectedCustomer] = useState<Partial<Customer>>({ id: '', name: '', phone: '' });
    const [exchangeRate, setExchangeRate] = useState<number>(260.00);
    const [isEditingRate, setIsEditingRate] = useState(false);

    // Estado de Pago
    const [paymentTab, setPaymentTab] = useState<'contado' | 'credito'>('contado');
    const [paymentMethod, setPaymentMethod] = useState<string>('Efectivo $');
    const [observation, setObservation] = useState('');

    // Estado Post-Venta (Recibo)
    const [completedSale, setCompletedSale] = useState<Sale | null>(null);
    const [showReceipt, setShowReceipt] = useState(false);

    // Refs
    const searchInputRef = useRef<HTMLInputElement>(null);

    // Filtrado visual (para la grilla), excluye búsqueda exacta si ya se procesó
    const filteredProducts = products.filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        p.sku.includes(searchTerm)
    );

    // --- CÁLCULOS ---
    const totalUSD = cart.reduce((acc, item) => acc + (item.product.price * item.qty), 0);
    const totalBs = totalUSD * exchangeRate;

    // Lógica de Financiamiento
    const creditPlan = React.useMemo(() => {
        if (paymentTab !== 'credito') return null;
        const initialPayment = totalUSD * 0.40; // 40% Inicial
        const remaining = totalUSD - initialPayment;
        const installmentsCount = 6;
        const installmentAmount = remaining / installmentsCount;
        const dates = calculatePaymentDates(new Date(), installmentsCount);

        return {
            initialPayment,
            remaining,
            installmentAmount,
            dates
        };
    }, [totalUSD, paymentTab]);

    // --- ACCIONES ---

    const addToCart = (product: Product) => {
        // Validación estricta de stock numérico
        const availableStock = Number(product.stock || 0);

        if (availableStock <= 0) {
            alert(`El producto "${product.name}" no tiene stock disponible.`);
            return;
        }

        const existing = cart.find(i => i.product.id === product.id);

        if (existing) {
            // Verificar si al sumar 1 superamos el stock
            if (existing.qty >= availableStock) {
                 alert(`Límite de stock alcanzado para "${product.name}".\n\nEn carrito: ${existing.qty}\nDisponible: ${availableStock}`);
                 return;
            }
            setCart(cart.map(i => i.product.id === product.id ? {...i, qty: i.qty + 1} : i));
        } else {
            setCart([...cart, {product, qty: 1}]);
        }
    };

    const removeFromCart = (productId: string) => {
        setCart(cart.filter(i => i.product.id !== productId));
    };

    // Manejador del Escáner (Enter)
    const handleSearchKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        // La prevención del formulario global se maneja en el onSubmit del form, 
        // pero mantenemos esto por seguridad adicional.
        if (e.key === 'Enter') {
            e.preventDefault(); 

            const term = searchTerm.trim();
            if (!term) return;

            // 1. PRIORIDAD MÁXIMA: Coincidencia EXACTA de SKU (IMEI)
            // Esto es crucial para SIMCARDS u otros productos donde el código es único.
            const exactImeiMatch = products.find(p => p.sku === term);

            if (exactImeiMatch) {
                addToCart(exactImeiMatch);
                setSearchTerm(''); // Limpiar inmediatamente para el siguiente escaneo
                return;
            } 

            // 2. Si no es IMEI exacto, buscamos coincidencia exacta por ID interno (fallback)
            const exactIdMatch = products.find(p => p.id === term);
            if (exactIdMatch) {
                addToCart(exactIdMatch);
                setSearchTerm('');
                return;
            }

            // 3. Si no hay coincidencia exacta, verificamos si el filtro visual arroja un único resultado
            if (filteredProducts.length === 1) {
                addToCart(filteredProducts[0]);
                setSearchTerm('');
                return;
            }

            // Si hay múltiples resultados o ninguno, no hacemos nada y dejamos que el usuario seleccione visualmente.
        }
    };

    const handleCheckout = () => {
        if (cart.length === 0) return;

        if (paymentTab === 'credito' && (!selectedCustomer.name || !selectedCustomer.phone)) {
            alert("Para ventas a crédito es obligatorio el nombre y teléfono del cliente.");
            return;
        }

        const sale: Sale = {
            id: Date.now().toString(),
            date: new Date().toISOString(),
