            msg += `\n*PLAN DE FINANCIAMIENTO:*\n`;
            msg += `🔹 Inicial (40%): $${creditPlan.initialPayment.toFixed(2)}\n`;
            msg += `🔹 Restante en 6 cuotas de: $${creditPlan.installmentAmount.toFixed(2)}\n`;
            msg += `📅 Fechas de pago: 15 y 30 de cada mes.\n`;
