                            <CheckCircle size={28} />
                        </div>
                        <h2 className="font-bold text-lg">¡Venta Exitosa!</h2>
                        <p className="text-sm opacity-90">Recibo generado correctamente</p>
                    </div>

                    {/* Receipt Preview */}
                    <div className="p-6 overflow-y-auto bg-gray-50 flex-1 custom-scrollbar">
