import { Product, Sale, Customer, User, ExternalApp, Purchase } from '../types';

// NOTA: Si esta URL da 404, la app funcionará en modo OFFLINE automáticamente.
const SHEETS_API_URL = 'https://script.google.com/macros/s/AKfycbzBpTxHOEPqvul1rdyGUESuG8WRcsHhmmDqphIVKRlwTefkeBSYyssPE7javZgLGmA_/exec'; 

export interface AppData {
  products: Product[];
  sales: Sale[];
  customers: Customer[];
  users: User[];
  apps: ExternalApp[];
}

// --- INITIAL MOCK DATA (Datos iniciales para que la app no arranque vacía) ---
let localData: AppData = {
    products: [
        { id: '1', name: 'IPHONE 14 PRO MAX', price: 1200.00, stock: 10, sku: 'PROD-001', category: 'Celulares' },
        { id: '2', name: 'CARGADOR 20W ORIGINAL', price: 25.00, stock: 50, sku: 'ACC-001', category: 'Accesorios' },
        { id: '3', name: 'FORRO SILICONE CASE', price: 10.00, stock: 100, sku: 'ACC-002', category: 'Accesorios' },
        { id: '4', name: 'REDMI NOTE 12', price: 180.00, stock: 15, sku: 'PROD-002', category: 'Celulares' },
        { id: '5', name: 'MICA CERAMICA', price: 5.00, stock: 200, sku: 'ACC-003', category: 'Accesorios' }
    ],
    sales: [],
    customers: [
        { id: 'V-12345678', name: 'Cliente Mostrador', phone: '000-0000000', email: '', address: '' }
    ],
    users: [
        { id: 'admin', name: 'Administrador', username: 'admin', role: 'admin', password: '123' },
        { id: 'vendedor', name: 'Vendedor 1', username: 'vendedor', role: 'seller', password: '123' }
    ],
    apps: []
};

// State flags
let isOfflineMode = false;

// --- HELPERS ---
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Normalizador seguro de números
const parseNumber = (value: any): number => {
    if (typeof value === 'number') return value;
    if (!value) return 0;
    // Elimina todo lo que no sea numero, punto o signo menos. Convierte coma en punto.
    const cleanStr = String(value).replace(/[^0-9.,-]/g, '').replace(',', '.');
    const num = parseFloat(cleanStr);
    return isNaN(num) ? 0 : num;
};

// Mapeador de datos de Google Sheets a nuestra estructura
const mapProductFromSheet = (raw: any): Product => ({
    id: String(raw.ID || raw.id || Date.now()),
    name: String(raw['NOMBRE DEL PRODUCTO'] || raw.NOMBRE || raw.Nombre || raw.name || 'Producto Sin Nombre'),
    price: parseNumber(raw.Precio || raw.PRECIO || raw.price),
    stock: parseNumber(raw.Stock || raw.STOCK || raw.stock),
    sku: String(raw.Imei || raw.IMEI || raw.sku || raw.Codigo || ''),
    category: String(raw.CATEGORIA || raw.Categoria || raw.category || 'General')
});

const formatSaleForSheet = (sale: Sale) => ({
    id: sale.id,
    date: sale.date,
    total: sale.total, 
    paymentMethod: sale.paymentMethod,
    paymentType: sale.paymentType,
    customerId: sale.customerId || '',
    customerName: sale.customerName || '',
    exchangeRate: sale.exchangeRate || 0,
    items: JSON.stringify(sale.items)
});

// --- API CORE ---

// Función genérica segura para peticiones
const safeFetch = async (action: string, sheet: string, data: any) => {
    if (isOfflineMode) {
        console.log(`[Offline Mode] Acción simulada: ${action} en ${sheet}`);
        return true;
    }

    try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 5000); // Timeout corto de 5s

        // Usamos no-cors porque Google Scripts no devuelve CORS headers en POST simples
        await fetch(SHEETS_API_URL, {
            method: 'POST',
            mode: 'no-cors',
            headers: { "Content-Type": "text/plain" },
            body: JSON.stringify({ action, sheet, data }),
            signal: controller.signal
        });

        clearTimeout(timeoutId);
        return true;
    } catch (error) {
        console.warn(`[Network] Falló sync con nube (${action}).`, error);
        // No lanzamos error para no romper la UI. Asumimos éxito local.
        return false;
    }
};

export const fetchAllData = async (): Promise<AppData> => {
  if (isOfflineMode) return localData;

  console.log("📥 Sincronizando datos...");
  try {
    const response = await fetch(SHEETS_API_URL, { method: 'GET', redirect: 'follow' });

    // Si la URL da 404 o 500, activamos modo offline
    if (!response.ok) {
        console.error(`❌ Error HTTP ${response.status}. Activando MODO OFFLINE.`);
        isOfflineMode = true;
        return localData;
    }

    const data = await response.json();

    // Validación básica de estructura
    if (!data || typeof data !== 'object') throw new Error("Respuesta inválida JSON");

    // Actualizamos caché local
    localData = {
        products: Array.isArray(data.products) ? data.products.map(mapProductFromSheet) : localData.products,
        sales: Array.isArray(data.sales) ? data.sales : localData.sales,
        customers: Array.isArray(data.customers) ? data.customers : localData.customers,
        users: Array.isArray(data.users) ? data.users : localData.users,
        apps: Array.isArray(data.apps) ? data.apps : localData.apps
    };

    console.log("✅ Datos sincronizados correctamente.");
    return localData;

  } catch (error) {
    console.warn("⚠️ No se pudo conectar a Google Sheets. Usando datos locales.", error);
    return localData;
  }
};

// --- API EXPORTS (Operations) ---

export const api = {
  // Operaciones de Venta (Actualizan local y envían a nube)
  processSaleTransaction: async (sale: Sale, updatedProducts: Product[]) => {
      // 1. Actualizar Localmente (Instantáneo)
      localData.sales.push(sale);
      localData.products = updatedProducts; // Reemplazamos el inventario con el ya calculado

      // 2. Enviar a Nube (Fuego y Olvido)
      // Enviamos la venta
      safeFetch('create', 'Sales', formatSaleForSheet(sale));

      // Enviamos actualización de stock por cada producto vendido
      // Pequeño delay entre peticiones para no saturar GAS
      for (const item of sale.items) {
          const product = updatedProducts.find(p => p.id === item.productId);
          if (product) {
              safeFetch('updateStock', 'Products', { id: product.id, stock: product.stock });
              await wait(100); 
          }
      }
      return true;
  },

  createPurchase: async (purchase: Purchase) => {
      return safeFetch('create', 'Purchases', { ...purchase, items: JSON.stringify(purchase.items) });
  },

  createCustomer: async (customer: Customer) => {
      // Check local duplicate
      if (!localData.customers.find(c => c.id === customer.id)) {
          localData.customers.push(customer);
          return safeFetch('create', 'Customers', customer);
      }
      return true;
  },

  createUser: async (user: User) => {
      localData.users.push(user);
      return safeFetch('create', 'Users', user);
  },

  createApp: async (app: ExternalApp) => {
      localData.apps.push(app);
      return safeFetch('create', 'Apps', app);
  },

  deleteApp: async (id: string) => {
      localData.apps = localData.apps.filter(a => a.id !== id);
      return safeFetch('delete', 'Apps', { id });
  },

  updateStockManual: async (id: string, newStock: number) => {
      const p = localData.products.find(x => x.id === id);
      if (p) p.stock = newStock;
      return safeFetch('updateStock', 'Products', { id, stock: newStock });
  }
};

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  ShoppingCart, 
  Package, 
  RotateCcw, 
  Grid, 
  Menu, 
  X, 
  LogOut, 
  CreditCard,
  Users,
  UserCircle,
  Loader2,
  RefreshCw,
  WifiOff
} from 'lucide-react';
import { Product, Sale, Purchase, ViewState, ExternalApp, Customer, User, Role } from './types';
import Dashboard from './components/Dashboard';
import AppLauncher from './components/AppLauncher';
import ChatBot from './components/ChatBot';
import Login from './components/Login';
import UsersView from './components/UsersView';
import CustomersView from './components/CustomersView';
import SalesView from './components/SalesView';
import PurchasesView from './components/PurchasesView';
import InventoryView from './components/InventoryView';
import { fetchAllData, api } from './services/api';

// -- INLINE COMPONENTS --
const ReturnsView = () => (
    <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-200 text-center">
        <RotateCcw className="w-16 h-16 text-orange-400 mx-auto mb-4" />
        <h2 className="text-2xl font-bold text-gray-800 mb-2">Gestión de Devoluciones</h2>
        <p className="text-gray-500 max-w-md mx-auto mb-6">Escanea el ticket de venta para iniciar garantía.</p>
    </div>
);

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);

  // Data State
  const [products, setProducts] = useState<Product[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [apps, setApps] = useState<ExternalApp[]>([]);

  // Initial Data Load
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setIsSyncing(true);
    try {
        const data = await fetchAllData();
        // Solo actualizamos si hay datos válidos, para no borrar el estado local con vacíos por error
        if (data.products.length > 0) setProducts(data.products);
        if (data.sales.length > 0) setSales(data.sales);
        if (data.customers.length > 0) setCustomers(data.customers);
        if (data.users.length > 0) setUsers(data.users);
        if (data.apps.length > 0) setApps(data.apps);
    } catch (e) {
        console.error("Error cargando datos (usando local)", e);
    } finally {
        setIsLoading(false);
        setIsSyncing(false);
    }
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'warehouse') setCurrentView('inventory');
    else if (user.role === 'seller') setCurrentView('sales');
    else setCurrentView('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  // --- CORE TRANSACTION LOGIC ---
  const handleNewSale = async (sale: Sale, customer?: Customer) => {
    console.log("🚀 Procesando Venta:", sale.id);

    // 1. Calcular el nuevo inventario en MEMORIA
    const updatedProducts = products.map(p => {
        const itemSold = sale.items.find(i => i.productId === p.id);
        if (itemSold) {
            // Protección contra NaN y números negativos
            const currentStock = typeof p.stock === 'number' ? p.stock : 0;
            return { ...p, stock: Math.max(0, currentStock - itemSold.quantity) };
        }
        return p;
    });

    // 2. Actualizar UI React Instántaneamente
    setProducts(updatedProducts);
    setSales(prev => [...prev, sale]);

    if (customer && customer.id) {
         if (!customers.find(c => c.id === customer.id)) {
             setCustomers(prev => [...prev, customer]);
         }
    }

    // 3. Enviar transacción al servicio API (Background)
    // Pasamos los productos YA actualizados para que la API sepa qué stock guardar
    await api.processSaleTransaction(sale, updatedProducts);

    if (customer) {
        api.createCustomer(customer);
    }
  };

  const handleNewPurchase = async (purchase: Purchase) => {
      await api.createPurchase(purchase);
      // En una app real, aquí también actualizaríamos el stock sumando
  };

  const handleUpdateStock = async (id: string, newStock: number) => {
      setProducts(products.map(p => p.id === id ? {...p, stock: newStock} : p));
      await api.updateStockManual(id, newStock);
  };

  const handleAddCustomer = async (customer: Customer) => {
      setCustomers(prev => [...prev, customer]);
      await api.createCustomer(customer);
  };

  const handleAddUser = async (user: User) => {
      setUsers(prev => [...prev, user]);
      await api.createUser(user);
  };

  const handleAddApp = async (app: ExternalApp) => {
      setApps(prev => [...prev, app]);
      await api.createApp(app);
  };

  const handleRemoveApp = async (id: string) => {
      setApps(prev => prev.filter(a => a.id !== id));
      await api.deleteApp(id);
  };

  // --- RENDER ---
  if (isLoading) {
      return (
          <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center">
              <Loader2 className="w-12 h-12 text-blue-600 animate-spin mb-4" />
              <h2 className="text-xl font-bold text-gray-700">Iniciando SistemCaja</h2>
              <p className="text-gray-400 mt-2">Cargando módulos...</p>
          </div>
      );
  }

  if (!currentUser) {
    // Si no hay usuarios cargados (primera vez offline), crear admin por defecto
    const authUsers = users.length > 0 ? users : [{id:'admin', name:'Admin Local', username:'admin', role:'admin' as Role, password:'123'}];
    return <Login onLogin={handleLogin} users={authUsers} />;
  }

  const NavItem = ({ view, icon: Icon, label, allowedRoles }: { view: ViewState, icon: any, label: string, allowedRoles: Role[] }) => {
    if (!allowedRoles.includes(currentUser.role)) return null;
    return (
        <button 
            onClick={() => setCurrentView(view)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 group
            ${currentView === view ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
        >
            <Icon size={20} className={`${currentView === view ? 'text-white' : 'text-slate-500 group-hover:text-white'}`} />
            {sidebarOpen && <span className="font-medium">{label}</span>}
        </button>
    );
  };

  if (currentView === 'sales') {
    return (
        <div className="h-screen bg-gray-50 flex font-sans overflow-hidden">
             <div className="w-16 bg-slate-900 text-white flex flex-col items-center py-4 z-50">
                <div className="mb-6 font-bold text-blue-400">SC</div>
                <div className="space-y-4 flex-1">
                    <button onClick={() => setCurrentView('dashboard')} className="p-2 hover:bg-slate-800 rounded text-slate-400 hover:text-white" title="Volver"><LayoutDashboard size={20}/></button>
                    <button onClick={() => setCurrentView('sales')} className="p-2 bg-blue-600 text-white rounded shadow-lg" title="Ventas"><ShoppingCart size={20}/></button>
                    <button onClick={() => setCurrentView('inventory')} className="p-2 hover:bg-slate-800 rounded text-slate-400 hover:text-white" title="Inventario"><Package size={20}/></button>
                </div>
                <button onClick={handleLogout} className="p-2 text-red-400 hover:bg-slate-800 rounded"><LogOut size={20}/></button>
             </div>
             <div className="flex-1 overflow-hidden relative">
                <SalesView products={products} customers={customers} onSale={handleNewSale} />
             </div>
        </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 flex font-sans">
        {/* Sidebar */}
        <div className={`bg-slate-900 text-white transition-all duration-300 flex flex-col ${sidebarOpen ? 'w-64' : 'w-20'}`}>
            <div className="h-16 flex items-center justify-between px-4 border-b border-slate-800">
                {sidebarOpen ? <h1 className="text-xl font-bold text-white">SistemCaja</h1> : <div className="font-bold">SC</div>}
                <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-1 text-slate-400"><Menu size={18} /></button>
            </div>

            <div className="p-4 border-b border-slate-800">
                 <div className="flex items-center gap-3">
                     <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center font-bold">
                         {currentUser.name.charAt(0)}
                     </div>
                     {sidebarOpen && <div className="text-sm font-medium truncate">{currentUser.name}</div>}
                 </div>
            </div>

            <nav className="flex-1 p-4 space-y-2 overflow-y-auto custom-scrollbar">
                <NavItem view="dashboard" icon={LayoutDashboard} label="Panel Principal" allowedRoles={['admin']} />
                <NavItem view="sales" icon={ShoppingCart} label="Caja / Ventas" allowedRoles={['admin', 'seller']} />
                <NavItem view="purchases" icon={CreditCard} label="Compras" allowedRoles={['admin']} />
                <NavItem view="inventory" icon={Package} label="Inventario" allowedRoles={['admin', 'warehouse']} />
                <NavItem view="returns" icon={RotateCcw} label="Devoluciones" allowedRoles={['admin', 'seller']} />
                <NavItem view="customers" icon={Users} label="Clientes" allowedRoles={['admin', 'seller']} />
                <NavItem view="apps" icon={Grid} label="Aplicaciones" allowedRoles={['admin', 'seller', 'warehouse']} />
                <NavItem view="users" icon={UserCircle} label="Usuarios" allowedRoles={['admin']} />
            </nav>

            <div className="p-4">
                <button onClick={loadData} className="flex items-center gap-2 text-slate-400 hover:text-white w-full p-2 mb-2">
                    <RefreshCw size={18} className={isSyncing ? 'animate-spin' : ''}/>
                    {sidebarOpen && (isSyncing ? 'Sincronizando...' : 'Recargar')}
                </button>
                <button onClick={handleLogout} className="flex items-center gap-2 text-red-400 hover:text-red-300 w-full p-2">
                    <LogOut size={18} />
                    {sidebarOpen && 'Salir'}
                </button>
            </div>
        </div>

        {/* Content */}
        <main className="flex-1 overflow-y-auto h-screen p-4 bg-slate-100">
            {currentView === 'dashboard' && <Dashboard sales={sales} />}
            {currentView === 'inventory' && <InventoryView products={products} onUpdateStock={handleUpdateStock} />}
            {currentView === 'apps' && <AppLauncher apps={apps} onAddApp={handleAddApp} onRemoveApp={handleRemoveApp} />}
            {currentView === 'customers' && <CustomersView customers={customers} onAddCustomer={handleAddCustomer} />}
            {currentView === 'users' && <UsersView users={users} onAddUser={handleAddUser} />}
            {currentView === 'returns' && <ReturnsView />}
            {currentView === 'purchases' && <PurchasesView onPurchase={handleNewPurchase} />}
        </main>

        <ChatBot />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Product, Sale, Customer } from '../types';
import { 
    Search, ShoppingCart, Smartphone, CheckCircle, CreditCard, 
    Smartphone as PhoneIcon, Printer, Share2, 
    RefreshCw, Edit2, User, X, AlertCircle
} from 'lucide-react';

interface SalesViewProps {
  products: Product[];
  customers: Customer[];
  onSale: (sale: Sale, customer?: Customer) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ products, customers, onSale }) => {
    // --- ESTADO ---
    const [cart, setCart] = useState<{product: Product, qty: number}[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedCustomer, setSelectedCustomer] = useState<Partial<Customer>>({ id: '', name: '', phone: '' });
    const [exchangeRate, setExchangeRate] = useState<number>(260.00);
    const [isEditingRate, setIsEditingRate] = useState(false);

    // Pago
    const [paymentTab, setPaymentTab] = useState<'contado' | 'credito'>('contado');
    const [paymentMethod, setPaymentMethod] = useState<string>('Efectivo $');
    const [observation, setObservation] = useState('');

    // Post-Venta
    const [completedSale, setCompletedSale] = useState<Sale | null>(null);
    const [showReceipt, setShowReceipt] = useState(false);

    const searchInputRef = useRef<HTMLInputElement>(null);

    // --- CÁLCULOS ---
    const totalUSD = cart.reduce((acc, item) => acc + (item.product.price * item.qty), 0);
    const totalBs = totalUSD * exchangeRate;

    // --- ACCIONES ---

    const addToCart = (product: Product) => {
        // Validación de Stock
        const existingItem = cart.find(i => i.product.id === product.id);
        const currentQtyInCart = existingItem ? existingItem.qty : 0;

        if (currentQtyInCart + 1 > product.stock) {
            alert("⚠️ Stock insuficiente para agregar más unidades.");
            return;
        }

        if (existingItem) {
            setCart(cart.map(i => i.product.id === product.id ? {...i, qty: i.qty + 1} : i));
        } else {
            setCart([...cart, {product, qty: 1}]);
        }
    };

    const removeFromCart = (index: number) => {
        const newCart = [...cart];
        newCart.splice(index, 1);
        setCart(newCart);
    };

    const handleSearch = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            const term = searchTerm.trim().toLowerCase();
            if(!term) return;

            // Búsqueda exacta primero (IMEI/SKU)
            const exact = products.find(p => p.sku.toLowerCase() === term || p.id === term);
            if (exact) {
                addToCart(exact);
                setSearchTerm('');
                return;
            }
            // Si no es exacta, no hacemos nada con Enter para no agregar items random
        }
    };

    const handleCheckout = () => {
        if (cart.length === 0) return;

        const sale: Sale = {
            id: Date.now().toString(),
            date: new Date().toISOString(),
            items: cart.map(i => ({
                productId: i.product.id,
                name: i.product.name,
                quantity: i.qty,
                priceAtSale: i.product.price
            })),
            total: totalUSD,
            paymentMethod: paymentTab === 'credito' ? 'Crédito' : paymentMethod,
            paymentType: paymentTab,
            customerId: selectedCustomer.id || 'GENERICO',
            customerName: selectedCustomer.name || 'Cliente Casual',
            exchangeRate: exchangeRate
        };

        const customerToSave = selectedCustomer.id && selectedCustomer.name ? {
            id: selectedCustomer.id,
            name: selectedCustomer.name,
            phone: selectedCustomer.phone || '',
            email: '',
            address: ''
        } : undefined;

        onSale(sale, customerToSave);
        setCompletedSale(sale);
        setShowReceipt(true);
    };

    const resetSale = () => {
        setCart([]);
        setSelectedCustomer({ id: '', name: '', phone: '' });
        setSearchTerm('');
        setCompletedSale(null);
        setShowReceipt(false);
        if(searchInputRef.current) searchInputRef.current.focus();
    };

    // --- RENDERIZADO DEL MODAL RECIBO ---
    const renderReceiptModal = () => (
        <div className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-xl overflow-hidden shadow-2xl">
                <div className="bg-green-600 p-4 text-center text-white">
                    <CheckCircle size={40} className="mx-auto mb-2"/>
                    <h2 className="text-xl font-bold">¡Venta Exitosa!</h2>
                </div>
                <div className="p-6 bg-gray-50 text-center space-y-4">
                    <div className="bg-white p-4 border border-dashed border-gray-300 rounded text-sm">
                        <p className="font-bold text-gray-800 text-lg mb-2">ACI MOVILNET</p>
                        <p>Total: <span className="font-bold text-xl">${completedSale?.total.toFixed(2)}</span></p>
                        <p className="text-gray-500">Bs. {(completedSale?.total || 0 * exchangeRate).toFixed(2)}</p>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <button onClick={() => window.print()} className="py-3 bg-gray-200 rounded-lg font-bold flex items-center justify-center gap-2"><Printer size={18}/> Imprimir</button>
                        <button className="py-3 bg-green-100 text-green-700 rounded-lg font-bold flex items-center justify-center gap-2"><Share2 size={18}/> WhatsApp</button>
                    </div>
                    <button onClick={resetSale} className="w-full py-3 bg-blue-600 text-white rounded-lg font-bold">Nueva Venta</button>
                </div>
            </div>
        </div>
    );

    // Filter products for grid
    const filteredProducts = products.filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        p.sku.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="h-full flex flex-col md:flex-row gap-4 p-4 bg-slate-100">
            {showReceipt && renderReceiptModal()}

            {/* IZQUIERDA: CATÁLOGO */}
            <div className="flex-[2] flex flex-col bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
                {/* Header Search */}
                <div className="p-4 border-b border-slate-100 flex gap-4 items-center">
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-3 text-gray-400" size={20}/>
                        <input 
                            ref={searchInputRef}
                            className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none"
                            placeholder="Buscar producto o escanear IMEI..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                            onKeyDown={handleSearch}
                            autoFocus
                        />
                    </div>
                    <div className="flex items-center gap-2 bg-slate-50 px-3 py-2 rounded-xl border border-slate-200">
                        <span className="text-xs font-bold text-gray-400">TASA BCV</span>
                        {isEditingRate ? (
                            <input 
                                className="w-16 bg-white border border-blue-300 rounded px-1 text-right font-bold"
                                autoFocus
                                onBlur={() => setIsEditingRate(false)}
                                value={exchangeRate}
                                onChange={e => setExchangeRate(Number(e.target.value))}
                            />
                        ) : (
                            <span onClick={() => setIsEditingRate(true)} className="font-bold text-lg cursor-pointer">Bs. {exchangeRate}</span>
                        )}
                    </div>
                </div>

                {/* Grid */}
                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar bg-slate-50">
                    <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                        {filteredProducts.map(p => {
                            const noStock = p.stock <= 0;
                            return (
                                <button 
                                    key={p.id} 
                                    disabled={noStock}
                                    onClick={() => addToCart(p)}
                                    className={`relative flex flex-col items-center p-4 bg-white rounded-xl border transition-all
                                        ${noStock ? 'opacity-60 grayscale border-gray-100' : 'hover:border-blue-400 hover:shadow-md border-gray-200'}
                                    `}
                                >
                                    <span className={`absolute top-2 right-2 text-[10px] font-bold px-2 py-0.5 rounded-full ${noStock ? 'bg-gray-200' : 'bg-green-100 text-green-700'}`}>
                                        {p.stock}
                                    </span>
                                    <div className="w-12 h-12 bg-slate-100 rounded-full flex items-center justify-center mb-3 text-slate-400">
                                        <Smartphone size={24}/>
                                    </div>
                                    <p className="text-sm font-bold text-slate-700 text-center line-clamp-2 leading-tight">{p.name}</p>
                                    <p className="mt-2 text-lg font-bold text-blue-600">${p.price}</p>
                                    {noStock && <div className="absolute inset-0 flex items-center justify-center bg-white/50 font-bold text-red-500 text-xs">AGOTADO</div>}
                                </button>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* DERECHA: CARRITO */}
            <div className="flex-1 max-w-md bg-white rounded-2xl border border-slate-200 shadow-xl flex flex-col overflow-hidden">
                <div className="bg-slate-900 text-white p-6">
                    <p className="text-slate-400 text-xs font-bold uppercase">Total a Pagar</p>
                    <div className="flex items-baseline gap-2">
                        <span className="text-4xl font-bold">${totalUSD.toFixed(2)}</span>
                        <span className="text-sm">USD</span>
                    </div>
                    <p className="text-emerald-400 font-mono mt-1">Bs. {totalBs.toLocaleString('es-VE')}</p>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-4">
                    {/* Lista Items */}
                    <div className="space-y-2">
                        {cart.length === 0 ? (
                            <div className="text-center py-8 text-gray-300 border-2 border-dashed rounded-xl">
                                <ShoppingCart className="mx-auto mb-2"/>
                                <p>Carrito Vacío</p>
                            </div>
                        ) : (
                            cart.map((item, idx) => (
                                <div key={idx} className="flex justify-between items-center p-2 bg-slate-50 rounded-lg group">
                                    <div className="flex items-center gap-3 overflow-hidden">
                                        <span className="w-6 h-6 bg-white border flex items-center justify-center text-xs font-bold rounded">{item.qty}</span>
                                        <div className="truncate">
                                            <p className="text-sm font-medium truncate">{item.product.name}</p>
                                            <p className="text-xs text-gray-500">${item.product.price}</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <span className="font-bold text-sm">${item.product.price * item.qty}</span>
                                        <button onClick={() => removeFromCart(idx)} className="text-gray-300 hover:text-red-500"><X size={16}/></button>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>

                    {/* Cliente */}
                    <div className="bg-white border rounded-xl p-3 space-y-2">
                        <div className="flex items-center gap-2 border-b pb-2">
                            <User size={16} className="text-gray-400"/>
                            <input 
                                className="flex-1 text-sm outline-none" 
                                placeholder="Cédula / ID Cliente"
                                value={selectedCustomer.id}
                                onChange={e => {
                                    const val = e.target.value;
                                    setSelectedCustomer(prev => ({...prev, id: val}));
                                    const found = customers.find(c => c.id === val);
                                    if(found) setSelectedCustomer(found);
                                }}
                            />
                        </div>
                        <input 
                            className="w-full text-sm outline-none px-6" 
                            placeholder="Nombre Cliente" 
                            value={selectedCustomer.name}
                            onChange={e => setSelectedCustomer(prev => ({...prev, name: e.target.value}))}
                        />
                    </div>

                    {/* Metodo Pago */}
                    <div className="grid grid-cols-3 gap-2">
                        {['Efectivo $', 'Pago Movil', 'Zelle', 'Tarjeta', 'Binance', 'Otro'].map(m => (
                            <button 
                                key={m}
                                onClick={() => setPaymentMethod(m)}
                                className={`py-2 text-xs font-bold rounded border ${paymentMethod === m ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-600 border-gray-200'}`}
                            >
                                {m}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="p-4 bg-white border-t">
                    <button 
                        onClick={handleCheckout}
                        disabled={cart.length === 0}
                        className="w-full py-4 bg-blue-600 hover:bg-blue-700 disabled:bg-gray-300 text-white font-bold rounded-xl shadow-lg transition-transform active:scale-95 flex items-center justify-center gap-2"
                    >
                        <CheckCircle size={20}/> COBRAR TOTAL
                    </button>
                </div>
            </div>
        </div>
    );
};

export default SalesView;

