import React, { useState, useEffect, useRef } from 'react';
import { Product, Sale, Customer } from '../types';
import { 
    Search, ShoppingCart, Smartphone, CheckCircle, CreditCard, 
    Smartphone as PhoneIcon, Printer, Share2, 
    RefreshCw, Edit2, User, X, AlertCircle, MapPin, Mail, Barcode
} from 'lucide-react';

interface SalesViewProps {
  products: Product[];
  customers: Customer[];
  onSale: (sale: Sale, customer?: Customer) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ products, customers, onSale }) => {
    // --- ESTADO ---
    const [cart, setCart] = useState<{product: Product, qty: number}[]>([]);
    const [searchTerm, setSearchTerm] = useState('');

    // Datos Completos del Cliente
    const [customerData, setCustomerData] = useState<Customer>({
        id: '',
        name: '',
        phone: '',
        email: '',
        address: ''
    });

    const [exchangeRate, setExchangeRate] = useState<number>(260.00);
    const [isEditingRate, setIsEditingRate] = useState(false);

    // Pago
    const [paymentTab, setPaymentTab] = useState<'contado' | 'credito'>('contado');
    const [paymentMethod, setPaymentMethod] = useState<string>('Efectivo $');

    // Post-Venta
    const [completedSale, setCompletedSale] = useState<Sale | null>(null);
    const [showReceipt, setShowReceipt] = useState(false);

    const searchInputRef = useRef<HTMLInputElement>(null);

    // --- CÁLCULOS ---
    const totalUSD = cart.reduce((acc, item) => acc + (item.product.price * item.qty), 0);
    const totalBs = totalUSD * exchangeRate;

    // --- ACCIONES ---

    const addToCart = (product: Product) => {
        // Usamos la forma funcional (prev => ...) para asegurar que siempre trabajamos 
        // con la versión más reciente del carrito, evitando que se sobrescriban items 
        // si se escanea muy rápido.
        setCart(prev => {
            const existingItem = prev.find(i => i.product.id === product.id);
            const currentQtyInCart = existingItem ? existingItem.qty : 0;

            if (currentQtyInCart + 1 > product.stock) {
                // Usamos un pequeño timeout para el alert para no bloquear el renderizado del estado
                setTimeout(() => alert(`⚠️ Stock insuficiente para ${product.name}. Disponible: ${product.stock}`), 10);
                return prev;
            }

            if (existingItem) {
                return prev.map(i => i.product.id === product.id ? {...i, qty: i.qty + 1} : i);
            } else {
                return [...prev, {product, qty: 1}];
            }
        });
    };

    const removeFromCart = (index: number) => {
        setCart(prev => {
            const newCart = [...prev];
            newCart.splice(index, 1);
            return newCart;
        });
    };

    const handleSearch = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            const term = searchTerm.trim().toLowerCase();
            if(!term) return;

            // Búsqueda exacta (Barcode scan o IMEI)
            const exact = products.find(p => p.sku.toLowerCase() === term || p.id === term);

            if (exact) {
                addToCart(exact);
                setSearchTerm(''); // Limpiar para el siguiente escaneo
                // Mantener el foco
                return;
            }

            // Si no es exacto, no hacemos nada (el usuario filtra visualmente en el grid)
        }
    };

    // Búsqueda de Cliente existente
    const handleCustomerSearch = (id: string) => {
        setCustomerData(prev => ({...prev, id}));
        const existing = customers.find(c => c.id === id);
        if (existing) {
            setCustomerData(existing);
        }
    };

    const handleCheckout = () => {
        if (cart.length === 0) return;

        // Validación básica de cliente si es crédito
        if (paymentTab === 'credito' && !customerData.name) {
            alert("Para ventas a crédito debe registrar el nombre del cliente.");
            return;
        }

        const sale: Sale = {
            id: Date.now().toString(),
            date: new Date().toISOString(),
            items: cart.map(i => ({
                productId: i.product.id,
                name: i.product.name,
                quantity: i.qty,
                priceAtSale: i.product.price
            })),
            total: totalUSD,
            paymentMethod: paymentTab === 'credito' ? 'Crédito' : paymentMethod,
            paymentType: paymentTab,
            customerId: customerData.id || 'GENERICO',
            customerName: customerData.name || 'Cliente Casual',
            exchangeRate: exchangeRate
        };

        const customerToSave: Customer | undefined = customerData.name ? {
            ...customerData,
            id: customerData.id || `C-${Date.now()}`
        } : undefined;

        onSale(sale, customerToSave);
        setCompletedSale(sale);
        setShowReceipt(true);
    };

    const resetSale = () => {
        setCart([]);
        setCustomerData({ id: '', name: '', phone: '', email: '', address: '' });
        setSearchTerm('');
        setCompletedSale(null);
        setShowReceipt(false);
        if(searchInputRef.current) searchInputRef.current.focus();
    };

    // --- RENDERIZADO DEL MODAL RECIBO ---
    const renderReceiptModal = () => (
        <div className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-xl overflow-hidden shadow-2xl animate-in zoom-in duration-200">
                <div className="bg-green-600 p-4 text-center text-white">
                    <CheckCircle size={40} className="mx-auto mb-2"/>
                    <h2 className="text-xl font-bold">¡Venta Registrada!</h2>
                </div>
                <div className="p-6 bg-gray-50 text-center space-y-4">
                    <div className="bg-white p-4 border border-dashed border-gray-300 rounded text-sm text-left">
                        <p className="font-bold text-gray-800 text-center mb-2 text-lg">TICKET DE VENTA</p>
                        <p className="flex justify-between"><span>Cliente:</span> <span className="font-bold">{completedSale?.customerName}</span></p>
                        <p className="flex justify-between"><span>Monto USD:</span> <span className="font-bold">${completedSale?.total.toFixed(2)}</span></p>
                        <p className="flex justify-between"><span>Monto Bs:</span> <span>Bs. {(completedSale?.total || 0 * exchangeRate).toFixed(2)}</span></p>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <button onClick={() => window.print()} className="py-3 bg-gray-200 rounded-lg font-bold flex items-center justify-center gap-2"><Printer size={18}/> Imprimir</button>
                        <button className="py-3 bg-green-100 text-green-700 rounded-lg font-bold flex items-center justify-center gap-2"><Share2 size={18}/> WhatsApp</button>
                    </div>
                    <button onClick={resetSale} className="w-full py-3 bg-blue-600 text-white rounded-lg font-bold">Nueva Venta</button>
                </div>
            </div>
        </div>
    );

    // Filter products
    const filteredProducts = products.filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        p.sku.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="h-full flex flex-col md:flex-row gap-4 p-4 bg-slate-100">
            {showReceipt && renderReceiptModal()}

            {/* IZQUIERDA: CATÁLOGO */}
            <div className="flex-[2] flex flex-col bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden h-full">
                {/* Header Search */}
                <div className="p-4 border-b border-slate-100 flex gap-4 items-center">
                    <div className="relative flex-1">
                        <Search className="absolute left-3 top-3 text-gray-400" size={20}/>
                        <input 
                            ref={searchInputRef}
                            className="w-full pl-10 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                            placeholder="Buscar producto o escanear IMEI..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                            onKeyDown={handleSearch}
                            autoFocus
                        />
                    </div>
                    <div className="flex items-center gap-2 bg-slate-50 px-3 py-2 rounded-xl border border-slate-200">
                        <span className="text-xs font-bold text-gray-400">TASA BCV</span>
                        {isEditingRate ? (
                            <input 
                                className="w-16 bg-white border border-blue-300 rounded px-1 text-right font-bold"
                                autoFocus
                                onBlur={() => setIsEditingRate(false)}
                                value={exchangeRate}
                                onChange={e => setExchangeRate(Number(e.target.value))}
                            />
                        ) : (
                            <span onClick={() => setIsEditingRate(true)} className="font-bold text-lg cursor-pointer text-slate-700">Bs. {exchangeRate}</span>
                        )}
                    </div>
                </div>

                {/* Grid */}
                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar bg-slate-50">
                    <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                        {filteredProducts.map(p => {
                            const noStock = p.stock <= 0;
                            return (
                                <button 
                                    key={p.id} 
                                    disabled={noStock}
                                    onClick={() => addToCart(p)}
                                    className={`relative flex flex-col items-center p-3 bg-white rounded-xl border transition-all duration-200 text-left
                                        ${noStock ? 'opacity-60 grayscale border-gray-100' : 'hover:border-blue-400 hover:shadow-lg hover:-translate-y-1 border-gray-200'}
                                    `}
                                >
                                    {/* Stock Badge */}
                                    <span className={`absolute top-2 right-2 text-[10px] font-bold px-2 py-0.5 rounded-full ${noStock ? 'bg-gray-200 text-gray-500' : 'bg-green-100 text-green-700'}`}>
                                        {p.stock} un.
                                    </span>

                                    {/* Icon */}
                                    <div className="w-10 h-10 bg-slate-50 rounded-full flex items-center justify-center mb-2 text-slate-400">
                                        <Smartphone size={20}/>
                                    </div>

                                    {/* Info */}
                                    <div className="w-full">
                                        <p className="text-xs font-bold text-slate-700 line-clamp-2 min-h-[2rem] leading-tight">{p.name}</p>

                                        {/* IMEI/SKU Display */}
                                        <div className="flex items-center gap-1 mt-1 mb-1">
                                            <Barcode size={10} className="text-gray-400" />
                                            <p className="text-[10px] text-gray-500 font-mono truncate bg-gray-50 px-1 rounded w-full">
                                                {p.sku || 'N/A'}
                                            </p>
                                        </div>

                                        <p className="text-lg font-black text-blue-600">${p.price}</p>
                                    </div>
                                </button>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* DERECHA: CARRITO Y DATOS CLIENTE */}
            <div className="flex-1 max-w-md bg-white rounded-2xl border border-slate-200 shadow-xl flex flex-col overflow-hidden h-full">

                {/* Total Header */}
                <div className="bg-slate-900 text-white p-6 relative overflow-hidden shrink-0">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500 rounded-full blur-3xl opacity-20 -mr-10 -mt-10"></div>
                    <p className="text-slate-400 text-xs font-bold uppercase tracking-wider">Total a Pagar</p>
                    <div className="flex items-baseline gap-2 mt-1">
                        <span className="text-4xl font-bold">${totalUSD.toFixed(2)}</span>
                        <span className="text-sm font-medium opacity-80">USD</span>
                    </div>
                    <p className="text-emerald-400 font-mono mt-1 text-sm font-bold">Bs. {totalBs.toLocaleString('es-VE')}</p>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar">

                    {/* Lista de Items */}
                    <div className="p-4 space-y-3 min-h-[150px]">
                        {cart.length === 0 ? (
                            <div className="h-full flex flex-col items-center justify-center text-gray-300 border-2 border-dashed border-gray-100 rounded-xl py-8">
                                <ShoppingCart size={40} className="mb-2 opacity-50"/>
                                <p className="text-sm font-medium">Carrito Vacío</p>
                            </div>
                        ) : (
                            cart.map((item, idx) => (
                                <div key={idx} className="flex justify-between items-center p-3 bg-slate-50 rounded-xl border border-slate-100 group">
                                    <div className="flex items-center gap-3 overflow-hidden">
                                        <span className="w-8 h-8 bg-white border border-gray-200 flex items-center justify-center text-sm font-bold rounded-lg text-slate-700 shadow-sm shrink-0">{item.qty}</span>
                                        <div className="overflow-hidden">
                                            <p className="text-sm font-bold text-slate-700 truncate">{item.product.name}</p>
                                            <p className="text-[10px] text-gray-500 font-mono">IMEI: {item.product.sku}</p>
                                            <p className="text-xs text-blue-600 font-medium">${item.product.price} c/u</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-3 pl-2">
                                        <span className="font-bold text-slate-800">${item.product.price * item.qty}</span>
                                        <button onClick={() => removeFromCart(idx)} className="text-gray-300 hover:text-red-500 transition-colors"><X size={18}/></button>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>

                    <div className="h-2 bg-gray-50 border-t border-b border-gray-100 shrink-0"></div>

                    {/* Datos del Cliente Completo */}
                    <div className="p-4 space-y-3">
                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Datos del Cliente</h3>

                        <div className="flex gap-2">
                            <div className="relative flex-[1]">
                                <User className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                                <input 
                                    className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                    placeholder="Cédula / RIF"
                                    value={customerData.id}
                                    onChange={e => handleCustomerSearch(e.target.value)}
                                />
                            </div>
                            <div className="relative flex-[2]">
                                <input 
                                    className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                    placeholder="Nombre Completo"
                                    value={customerData.name}
                                    onChange={e => setCustomerData({...customerData, name: e.target.value})}
                                />
                            </div>
                        </div>

                        <div className="flex gap-2">
                            <div className="relative flex-1">
                                <PhoneIcon className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                                <input 
                                    className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                    placeholder="Teléfono"
                                    value={customerData.phone}
                                    onChange={e => setCustomerData({...customerData, phone: e.target.value})}
                                />
                            </div>
                            <div className="relative flex-1">
                                <Mail className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                                <input 
                                    className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                    placeholder="Email"
                                    value={customerData.email}
                                    onChange={e => setCustomerData({...customerData, email: e.target.value})}
                                />
                            </div>
                        </div>

                        <div className="relative">
                            <MapPin className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                            <input 
                                className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                placeholder="Dirección Fiscal"
                                value={customerData.address}
                                onChange={e => setCustomerData({...customerData, address: e.target.value})}
                            />
                        </div>
                    </div>
                </div>

                {/* Footer Payment & Action */}
                <div className="p-4 bg-white border-t border-gray-100 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] z-10 shrink-0">
                    <div className="mb-3">
                         <div className="grid grid-cols-3 gap-2">
                            {['Efectivo $', 'Pago Movil', 'Zelle', 'Punto', 'Binance', 'Otro'].map(m => (
                                <button 
                                    key={m}
                                    onClick={() => setPaymentMethod(m)}
                                    className={`py-2 text-[10px] uppercase font-bold rounded-lg border transition-all ${paymentMethod === m ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}
                                >
                                    {m}
                                </button>
                            ))}
                        </div>
                    </div>
                    <button 
                        onClick={handleCheckout}
                        disabled={cart.length === 0}
                        className="w-full py-3.5 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 disabled:from-gray-300 disabled:to-gray-400 disabled:cursor-not-allowed text-white font-bold rounded-xl shadow-lg shadow-blue-200 transition-all active:scale-95 flex items-center justify-center gap-2"
                    >
                        <CheckCircle size={20}/> PROCESAR VENTA
                    </button>
                </div>
            </div>
        </div>
    );
};

export default SalesView;

import React, { useState, useEffect, useRef } from 'react';
import { Product, Sale, Customer } from '../types';
import { 
    Search, ShoppingCart, Smartphone, CheckCircle, CreditCard, 
    Smartphone as PhoneIcon, Printer, Share2, 
    RefreshCw, Edit2, User, X, AlertCircle, MapPin, Mail, Barcode, ScanBarcode
} from 'lucide-react';

interface SalesViewProps {
  products: Product[];
  customers: Customer[];
  onSale: (sale: Sale, customer?: Customer) => void;
}

const SalesView: React.FC<SalesViewProps> = ({ products, customers, onSale }) => {
    // --- ESTADO ---
    const [cart, setCart] = useState<{product: Product, qty: number}[]>([]);
    const [searchTerm, setSearchTerm] = useState('');

    // Datos Completos del Cliente
    const [customerData, setCustomerData] = useState<Customer>({
        id: '',
        name: '',
        phone: '',
        email: '',
        address: ''
    });

    const [exchangeRate, setExchangeRate] = useState<number>(260.00);
    const [isEditingRate, setIsEditingRate] = useState(false);

    // Pago
    const [paymentTab, setPaymentTab] = useState<'contado' | 'credito'>('contado');
    const [paymentMethod, setPaymentMethod] = useState<string>('Efectivo $');

    // Post-Venta
    const [completedSale, setCompletedSale] = useState<Sale | null>(null);
    const [showReceipt, setShowReceipt] = useState(false);

    const searchInputRef = useRef<HTMLInputElement>(null);

    // --- EFECTOS DE FOCO ---
    // Mantiene el foco en el buscador a menos que estemos editando datos de cliente
    useEffect(() => {
        if (!showReceipt && !isEditingRate) {
            const timer = setTimeout(() => {
                // Solo enfocar si el usuario no está escribiendo en campos de cliente
                const activeEl = document.activeElement;
                const isCustomerInput = activeEl?.tagName === 'INPUT' && activeEl.getAttribute('placeholder') !== 'Buscar producto o escanear IMEI...';

                if (!isCustomerInput && searchInputRef.current) {
                    searchInputRef.current.focus();
                }
            }, 100);
            return () => clearTimeout(timer);
        }
    }, [cart, showReceipt]); // Re-enfocar cuando el carrito cambia

    // --- CÁLCULOS ---
    const totalUSD = cart.reduce((acc, item) => acc + (item.product.price * item.qty), 0);
    const totalBs = totalUSD * exchangeRate;

    // --- ACCIONES ---

    const addToCart = (product: Product) => {
        setCart(prev => {
            const existingItem = prev.find(i => i.product.id === product.id);
            const currentQtyInCart = existingItem ? existingItem.qty : 0;
            const availableStock = Number(product.stock) || 0;

            if (currentQtyInCart + 1 > availableStock) {
                // Usamos alert nativo para bloquear momentáneamente y avisar
                alert(`⚠️ Stock insuficiente para ${product.name}. Disponible: ${availableStock}`);
                return prev;
            }

            if (existingItem) {
                return prev.map(i => i.product.id === product.id ? {...i, qty: i.qty + 1} : i);
            } else {
                return [...prev, {product, qty: 1}];
            }
        });

        // Limpiar búsqueda y recuperar foco inmediatamente
        setSearchTerm('');
        if(searchInputRef.current) searchInputRef.current.focus();
    };

    const removeFromCart = (index: number) => {
        setCart(prev => {
            const newCart = [...prev];
            newCart.splice(index, 1);
            return newCart;
        });
        if(searchInputRef.current) searchInputRef.current.focus();
    };

    const handleSearch = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            e.preventDefault(); // Evitar comportamientos extraños del navegador
            const term = searchTerm.trim().toLowerCase();
            if(!term) return;

            // 1. Buscar coincidencia exacta (Escáner de Barras / IMEI)
            const exact = products.find(p => 
                String(p.sku).toLowerCase() === term || 
                String(p.id) === term
            );

            if (exact) {
                addToCart(exact);
                return;
            }

            // Si no es exacto, el filtro visual ya hizo su trabajo.
            // Si el usuario da Enter y solo hay 1 resultado visible, lo agregamos (comodidad)
            const visible = products.filter(p => 
                p.name.toLowerCase().includes(term) || 
                p.sku.toLowerCase().includes(term)
            );

            if (visible.length === 1) {
                addToCart(visible[0]);
            }
        }
    };

    // Búsqueda de Cliente existente
    const handleCustomerSearch = (id: string) => {
        setCustomerData(prev => ({...prev, id}));
        const existing = customers.find(c => c.id === id);
        if (existing) {
            setCustomerData(existing);
        }
    };

    const handleCheckout = () => {
        if (cart.length === 0) return;

        if (paymentTab === 'credito' && !customerData.name) {
            alert("Para ventas a crédito debe registrar el nombre del cliente.");
            return;
        }

        const sale: Sale = {
            id: Date.now().toString(),
            date: new Date().toISOString(),
            items: cart.map(i => ({
                productId: i.product.id,
                name: i.product.name,
                quantity: i.qty,
                priceAtSale: i.product.price
            })),
            total: totalUSD,
            paymentMethod: paymentTab === 'credito' ? 'Crédito' : paymentMethod,
            paymentType: paymentTab,
            customerId: customerData.id || 'GENERICO',
            customerName: customerData.name || 'Cliente Casual',
            exchangeRate: exchangeRate
        };

        const customerToSave: Customer | undefined = customerData.name ? {
            ...customerData,
            id: customerData.id || `C-${Date.now()}`
        } : undefined;

        onSale(sale, customerToSave);
        setCompletedSale(sale);
        setShowReceipt(true);
    };

    const resetSale = () => {
        setCart([]);
        setCustomerData({ id: '', name: '', phone: '', email: '', address: '' });
        setSearchTerm('');
        setCompletedSale(null);
        setShowReceipt(false);
        // Forzar foco al reiniciar
        setTimeout(() => searchInputRef.current?.focus(), 100);
    };

    // Filter products visualmente
    const filteredProducts = products.filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
        p.sku.toLowerCase().includes(searchTerm.toLowerCase())
    );

    // --- RENDERIZADO DEL MODAL RECIBO ---
    const renderReceiptModal = () => (
        <div className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center p-4">
            <div className="bg-white w-full max-w-sm rounded-xl overflow-hidden shadow-2xl animate-in zoom-in duration-200">
                <div className="bg-green-600 p-4 text-center text-white">
                    <CheckCircle size={40} className="mx-auto mb-2"/>
                    <h2 className="text-xl font-bold">¡Venta Registrada!</h2>
                </div>
                <div className="p-6 bg-gray-50 text-center space-y-4">
                    <div className="bg-white p-4 border border-dashed border-gray-300 rounded text-sm text-left">
                        <p className="font-bold text-gray-800 text-center mb-2 text-lg">TICKET DE VENTA</p>
                        <p className="flex justify-between"><span>Cliente:</span> <span className="font-bold">{completedSale?.customerName}</span></p>
                        <p className="flex justify-between"><span>Monto USD:</span> <span className="font-bold">${completedSale?.total.toFixed(2)}</span></p>
                        <p className="flex justify-between"><span>Monto Bs:</span> <span>Bs. {(completedSale?.total || 0 * exchangeRate).toFixed(2)}</span></p>
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                        <button onClick={() => window.print()} className="py-3 bg-gray-200 rounded-lg font-bold flex items-center justify-center gap-2"><Printer size={18}/> Imprimir</button>
                        <button className="py-3 bg-green-100 text-green-700 rounded-lg font-bold flex items-center justify-center gap-2"><Share2 size={18}/> WhatsApp</button>
                    </div>
                    <button onClick={resetSale} className="w-full py-3 bg-blue-600 text-white rounded-lg font-bold">Nueva Venta</button>
                </div>
            </div>
        </div>
    );

    return (
        <div className="h-full flex flex-col md:flex-row gap-4 p-4 bg-slate-100">
            {showReceipt && renderReceiptModal()}

            {/* IZQUIERDA: CATÁLOGO */}
            <div className="flex-[2] flex flex-col bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden h-full">
                {/* Header Search */}
                <div className="p-4 border-b border-slate-100 flex gap-4 items-center bg-slate-50">
                    <div className="relative flex-1">
                        <ScanBarcode className="absolute left-3 top-3 text-blue-500" size={20}/>
                        <input 
                            ref={searchInputRef}
                            className="w-full pl-10 pr-4 py-3 bg-white border-2 border-blue-100 rounded-xl focus:ring-4 focus:ring-blue-200 focus:border-blue-500 outline-none transition-all font-medium text-lg placeholder:text-slate-400"
                            placeholder="ESCANEAR IMEI O CÓDIGO AQUÍ..."
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                            onKeyDown={handleSearch}
                            autoFocus
                            autoComplete="off"
                        />
                    </div>
                    <div className="flex items-center gap-2 bg-white px-4 py-2 rounded-xl border border-slate-200 shadow-sm">
                        <span className="text-xs font-bold text-gray-500">TASA BCV</span>
                        {isEditingRate ? (
                            <input 
                                className="w-20 bg-gray-50 border border-blue-300 rounded px-2 py-1 text-right font-bold text-lg"
                                autoFocus
                                onBlur={() => setIsEditingRate(false)}
                                value={exchangeRate}
                                onChange={e => setExchangeRate(Number(e.target.value))}
                            />
                        ) : (
                            <button onClick={() => setIsEditingRate(true)} className="font-bold text-xl text-slate-800 hover:text-blue-600">
                                Bs. {exchangeRate}
                            </button>
                        )}
                    </div>
                </div>

                {/* Grid */}
                <div className="flex-1 overflow-y-auto p-4 custom-scrollbar bg-slate-50">
                    <div className="grid grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
                        {filteredProducts.map(p => {
                            const noStock = p.stock <= 0;
                            return (
                                <button 
                                    key={p.id} 
                                    disabled={noStock}
                                    onClick={() => addToCart(p)}
                                    className={`relative flex flex-col p-0 bg-white rounded-xl border transition-all duration-200 text-left overflow-hidden group
                                        ${noStock ? 'opacity-60 grayscale border-gray-100' : 'hover:border-blue-500 hover:shadow-xl hover:-translate-y-1 border-gray-200 shadow-sm'}
                                    `}
                                >
                                    {/* IMEI / SKU STRIP - MUY VISIBLE */}
                                    <div className="bg-yellow-100 w-full px-3 py-1 border-b border-yellow-200 flex items-center gap-2">
                                        <Barcode size={14} className="text-yellow-700 opacity-70" />
                                        <span className="font-mono font-bold text-xs text-yellow-900 truncate tracking-wide">
                                            {p.sku || 'SIN IMEI'}
                                        </span>
                                    </div>

                                    <div className="p-4 flex flex-col gap-2 flex-1">
                                        <div className="flex justify-between items-start">
                                            <div className="w-10 h-10 bg-slate-100 rounded-lg flex items-center justify-center text-slate-400 group-hover:bg-blue-50 group-hover:text-blue-500 transition-colors">
                                                <Smartphone size={20}/>
                                            </div>
                                            <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${noStock ? 'bg-gray-100 text-gray-500' : 'bg-green-100 text-green-700'}`}>
                                                {p.stock} disp.
                                            </span>
                                        </div>

                                        <p className="text-sm font-bold text-slate-700 line-clamp-2 leading-tight min-h-[2.5rem] mt-1">
                                            {p.name}
                                        </p>

                                        <div className="mt-auto pt-2 flex justify-between items-end border-t border-gray-50">
                                             <p className="text-xl font-black text-blue-600">${p.price}</p>
                                             <div className="w-6 h-6 rounded-full bg-blue-600 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                                 <CheckCircle size={14} />
                                             </div>
                                        </div>
                                    </div>
                                </button>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* DERECHA: CARRITO Y DATOS CLIENTE */}
            <div className="flex-1 max-w-md bg-white rounded-2xl border border-slate-200 shadow-xl flex flex-col overflow-hidden h-full">

                {/* Total Header */}
                <div className="bg-slate-900 text-white p-6 relative overflow-hidden shrink-0">
                    <div className="absolute top-0 right-0 w-32 h-32 bg-blue-500 rounded-full blur-3xl opacity-20 -mr-10 -mt-10"></div>
                    <p className="text-slate-400 text-xs font-bold uppercase tracking-wider">Total a Pagar</p>
                    <div className="flex items-baseline gap-2 mt-1">
                        <span className="text-4xl font-bold">${totalUSD.toFixed(2)}</span>
                        <span className="text-sm font-medium opacity-80">USD</span>
                    </div>
                    <p className="text-emerald-400 font-mono mt-1 text-sm font-bold">Bs. {totalBs.toLocaleString('es-VE')}</p>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar">

                    {/* Lista de Items */}
                    <div className="p-4 space-y-3 min-h-[150px]">
                        {cart.length === 0 ? (
                            <div className="h-full flex flex-col items-center justify-center text-gray-300 border-2 border-dashed border-gray-100 rounded-xl py-8">
                                <ShoppingCart size={40} className="mb-2 opacity-50"/>
                                <p className="text-sm font-medium">Carrito Vacío</p>
                                <p className="text-xs mt-1">Escanee un producto para comenzar</p>
                            </div>
                        ) : (
                            cart.map((item, idx) => (
                                <div key={idx} className="flex justify-between items-center p-3 bg-white rounded-xl border border-slate-200 shadow-sm group hover:border-blue-300 transition-colors">
                                    <div className="flex items-center gap-3 overflow-hidden">
                                        <span className="w-8 h-8 bg-slate-100 border border-slate-200 flex items-center justify-center text-sm font-bold rounded-lg text-slate-700 shrink-0">
                                            {item.qty}
                                        </span>
                                        <div className="overflow-hidden">
                                            <p className="text-sm font-bold text-slate-800 truncate">{item.product.name}</p>
                                            <p className="text-[10px] text-gray-500 font-mono flex items-center gap-1">
                                                <Barcode size={10} /> {item.product.sku}
                                            </p>
                                            <p className="text-xs text-blue-600 font-medium">${item.product.price} c/u</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-3 pl-2">
                                        <span className="font-bold text-slate-800">${item.product.price * item.qty}</span>
                                        <button onClick={() => removeFromCart(idx)} className="text-gray-300 hover:text-red-500 transition-colors p-1.5 hover:bg-red-50 rounded-full">
                                            <X size={18}/>
                                        </button>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>

                    <div className="h-2 bg-gray-50 border-t border-b border-gray-100 shrink-0"></div>

                    {/* Datos del Cliente Completo */}
                    <div className="p-4 space-y-3">
                        <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">Datos del Cliente</h3>

                        <div className="flex gap-2">
                            <div className="relative flex-[1]">
                                <User className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                                <input 
                                    className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                    placeholder="Cédula / RIF"
                                    value={customerData.id}
                                    onChange={e => handleCustomerSearch(e.target.value)}
                                />
                            </div>
                            <div className="relative flex-[2]">
                                <input 
                                    className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                    placeholder="Nombre Completo"
                                    value={customerData.name}
                                    onChange={e => setCustomerData({...customerData, name: e.target.value})}
                                />
                            </div>
                        </div>

                        <div className="flex gap-2">
                            <div className="relative flex-1">
                                <PhoneIcon className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                                <input 
                                    className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                    placeholder="Teléfono"
                                    value={customerData.phone}
                                    onChange={e => setCustomerData({...customerData, phone: e.target.value})}
                                />
                            </div>
                            <div className="relative flex-1">
                                <Mail className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                                <input 
                                    className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                    placeholder="Email"
                                    value={customerData.email}
                                    onChange={e => setCustomerData({...customerData, email: e.target.value})}
                                />
                            </div>
                        </div>

                        <div className="relative">
                            <MapPin className="absolute left-3 top-2.5 text-gray-400 w-4 h-4" />
                            <input 
                                className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-lg text-sm outline-none focus:border-blue-500 transition-colors"
                                placeholder="Dirección Fiscal"
                                value={customerData.address}
                                onChange={e => setCustomerData({...customerData, address: e.target.value})}
                            />
                        </div>
                    </div>
                </div>

                {/* Footer Payment & Action */}
                <div className="p-4 bg-white border-t border-gray-100 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)] z-10 shrink-0">
                    <div className="mb-3">
                         <div className="grid grid-cols-3 gap-2">
                            {['Efectivo $', 'Pago Movil', 'Zelle', 'Punto', 'Binance', 'Otro'].map(m => (
                                <button 
                                    key={m}
                                    onClick={() => setPaymentMethod(m)}
                                    className={`py-2 text-[10px] uppercase font-bold rounded-lg border transition-all ${paymentMethod === m ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}
                                >
                                    {m}
                                </button>
                            ))}
                        </div>
                    </div>
                    <button 
                        onClick={handleCheckout}
                        disabled={cart.length === 0}
                        className="w-full py-3.5 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 disabled:from-gray-300 disabled:to-gray-400 disabled:cursor-not-allowed text-white font-bold rounded-xl shadow-lg shadow-blue-200 transition-all active:scale-95 flex items-center justify-center gap-2"
                    >
                        <CheckCircle size={20}/> PROCESAR VENTA
                    </button>
                </div>
            </div>
        </div>
    );
};

export default SalesView;

import { Product, Sale, Customer, User, ExternalApp, Purchase } from '../types';

const SHEETS_API_URL = 'https://script.google.com/macros/s/AKfycbzBpTxHOEPqvul1rdyGUESuG8WRcsHhmmDqphIVKRlwTefkeBSYyssPE7javZgLGmA_/exec'; 
const CACHE_KEY = 'sistemcaja_local_db';

export interface AppData {
  products: Product[];
  sales: Sale[];
  customers: Customer[];
  users: User[];
  apps: ExternalApp[];
}

// --- LOCAL DATA (Estado Inicial) ---
let localData: AppData = {
    products: [],
    sales: [],
    customers: [],
    users: [],
    apps: []
};

// --- HELPERS ---
const parseNumber = (value: any): number => {
    if (typeof value === 'number') return value;
    if (!value) return 0;
    const cleanStr = String(value).replace(/[^0-9.,-]/g, '').replace(',', '.');
    const num = parseFloat(cleanStr);
    return isNaN(num) ? 0 : num;
};

const mapProductFromSheet = (raw: any): Product => ({
    id: String(raw.ID || raw.id || Date.now()),
    name: String(raw['NOMBRE DEL PRODUCTO'] || raw.NOMBRE || raw.Nombre || raw.name || 'Producto Sin Nombre'),
    price: parseNumber(raw.Precio || raw.PRECIO || raw.price),
    stock: parseNumber(raw.Stock || raw.STOCK || raw.stock),
    sku: String(raw.Imei || raw.IMEI || raw.sku || raw.Codigo || ''),
    category: String(raw.CATEGORIA || raw.Categoria || raw.category || 'General')
});

const formatSaleForSheet = (sale: Sale) => ({
    id: sale.id,
    date: sale.date,
    total: sale.total, 
    paymentMethod: sale.paymentMethod,
    paymentType: sale.paymentType,
    customerId: sale.customerId || '',
    customerName: sale.customerName || '',
    exchangeRate: sale.exchangeRate || 0,
    items: JSON.stringify(sale.items)
});

// --- CACHE MANAGEMENT ---
const saveToCache = (data: AppData) => {
    try {
        localStorage.setItem(CACHE_KEY, JSON.stringify(data));
    } catch (e) {
        console.error("Error guardando en caché", e);
    }
};

const loadFromCache = (): AppData | null => {
    try {
        const cached = localStorage.getItem(CACHE_KEY);
        return cached ? JSON.parse(cached) : null;
    } catch (e) {
        return null;
    }
};

// --- API IMPLEMENTATION ---

export const fetchAllData = async (): Promise<AppData> => {
  console.log("📥 Obteniendo datos...");

  // 1. Intentar cargar desde caché primero para mostrar algo rápido (Estrategia Stale-While-Revalidate)
  const cachedData = loadFromCache();
  if (cachedData) {
      console.log("⚡ Datos cargados desde caché local");
      localData = cachedData; // Actualizamos la variable local inmediatamente
  }

  try {
    // 2. Intentar conectar con Google Sheets
    const response = await fetch(SHEETS_API_URL, { 
        method: 'GET', 
        redirect: 'follow'
    });

    if (!response.ok) throw new Error("Error HTTP " + response.status);

    const text = await response.text();
    // Validar que no sea un error HTML de Google
    if (text.startsWith('<') || text.includes('DOCTYPE')) {
        throw new Error("Google Script devolvió HTML en lugar de JSON (Posible error de cuota/bloqueo)");
    }

    const data = JSON.parse(text);

    // 3. Si Google responde bien, actualizamos la "Verdad" y guardamos en caché
    const freshData: AppData = {
        products: Array.isArray(data.products) ? data.products.map(mapProductFromSheet) : [],
        sales: data.sales || [],
        customers: data.customers || [],
        users: data.users || [],
        apps: data.apps || []
    };

    // Validación básica para no borrar datos si llega vacío por error
    if (freshData.products.length > 0) {
        saveToCache(freshData);
        localData = freshData;
        console.log("✅ Datos sincronizados con la nube");
    } else {
        console.warn("⚠️ La nube devolvió 0 productos. Manteniendo caché local si existe.");
        if (cachedData) return cachedData;
    }

    return localData;

  } catch (error) {
    console.warn("⚠️ Error conectando con Google Sheets. Usando modo Offline.", error);
    // 4. Si falla la red, devolvemos el caché (si existe) o la variable local
    if (cachedData) return cachedData;
    return localData;
  }
};

// Función para enviar datos "a ciegas" (Fire and Forget)
const sendToSheet = async (action: string, sheet: string, data: any) => {
    try {
        // Usamos no-cors para evitar esperar la respuesta y prevenir el bloqueo del navegador
        await fetch(SHEETS_API_URL, {
            method: 'POST',
            mode: 'no-cors', 
            headers: { "Content-Type": "text/plain" },
            body: JSON.stringify({ action, sheet, data }),
            keepalive: true 
        });
        console.log(`✅ Enviado (Background): ${action} ${sheet}`);
        return true;
    } catch (e) {
        // Los errores de red aquí son esperados si se recarga rápido, no afectan la lógica local
        console.error(`❌ Error envío fondo: ${action}`, e);
        return false;
    }
};

export const api = {
  createSale: async (sale: Sale) => {
    return sendToSheet('create', 'Sales', formatSaleForSheet(sale));
  },

  updateStock: async (id: string, newStock: number) => {
    return sendToSheet('updateStock', 'Products', { id, stock: newStock });
  },

  createPurchase: async (purchase: Purchase) => {
    const payload = { ...purchase, items: JSON.stringify(purchase.items) };
    return sendToSheet('create', 'Purchases', payload);
  },

  createCustomer: async (customer: Customer) => {
    return sendToSheet('create', 'Customers', customer);
  },

  createUser: async (user: User) => {
    return sendToSheet('create', 'Users', user);
  },

  createApp: async (app: ExternalApp) => {
    return sendToSheet('create', 'Apps', app);
  },

  deleteApp: async (id: string) => {
      return sendToSheet('delete', 'Apps', { id });
  }
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Product } from '../types';
import { 
    Search, Barcode, CheckCircle, AlertTriangle, 
    Package, XCircle, History, Trash2, ScanLine
} from 'lucide-react';

interface InventoryViewProps {
  products: Product[];
  onUpdateStock: (id: string, qty: number) => void;
}

type ScanSessionItem = {
    timestamp: number;
    sku: string;
    product?: Product;
    status: 'found' | 'not_found';
};

const InventoryView: React.FC<InventoryViewProps> = ({ products, onUpdateStock }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [lastScan, setLastScan] = useState<ScanSessionItem | null>(null);
  const [sessionHistory, setSessionHistory] = useState<ScanSessionItem[]>([]);

  const inputRef = useRef<HTMLInputElement>(null);

  // Mantener foco siempre en el input
  useEffect(() => {
    const focusInterval = setInterval(() => {
        if (document.activeElement !== inputRef.current) {
            inputRef.current?.focus();
        }
    }, 500);
    return () => clearInterval(focusInterval);
  }, []);

  const handleScan = (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter') {
          const code = searchTerm.trim();
          if (!code) return;

          // Buscar producto exacto por IMEI/SKU o ID
          const product = products.find(p => 
              String(p.sku).toLowerCase() === code.toLowerCase() || 
              String(p.id) === code
          );

          const scanResult: ScanSessionItem = {
              timestamp: Date.now(),
              sku: code,
              product: product,
              status: product ? 'found' : 'not_found'
          };

          setLastScan(scanResult);
          setSessionHistory(prev => [scanResult, ...prev]);
          setSearchTerm(''); // Limpiar para el siguiente
      }
  };

  const clearSession = () => {
      setSessionHistory([]);
      setLastScan(null);
      setSearchTerm('');
      inputRef.current?.focus();
  };

  // Renderizado del resultado principal (Tarjeta Grande)
  const renderResultCard = () => {
      if (!lastScan) {
          return (
              <div className="flex flex-col items-center justify-center h-64 text-gray-400 border-2 border-dashed border-gray-200 rounded-2xl bg-gray-50/50">
                  <ScanLine size={64} className="mb-4 opacity-20" />
                  <h3 className="text-xl font-bold text-gray-500">Esperando Escaneo...</h3>
                  <p className="text-sm">Escanea un código de barras o IMEI para ver detalles</p>
              </div>
          );
      }

      if (lastScan.status === 'not_found') {
          return (
              <div className="bg-red-50 border-2 border-red-100 rounded-2xl p-8 text-center animate-in zoom-in duration-200">
                  <XCircle size={64} className="text-red-500 mx-auto mb-4" />
                  <h2 className="text-3xl font-bold text-red-700 mb-2">Producto No Encontrado</h2>
                  <p className="text-red-500 font-mono text-lg">Código escaneado: {lastScan.sku}</p>
              </div>
          );
      }

      const p = lastScan.product!;
      const isLowStock = p.stock <= 2;

      return (
          <div className="bg-white border border-blue-100 rounded-2xl shadow-xl overflow-hidden animate-in zoom-in duration-200">
              <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-6 text-white flex justify-between items-start">
                  <div>
                      <h2 className="text-2xl font-bold leading-tight">{p.name}</h2>
                      <p className="text-blue-100 mt-1 opacity-90">{p.category}</p>
                  </div>
                  <div className="bg-white/20 p-2 rounded-lg backdrop-blur-sm">
                      <Package size={32} className="text-white" />
                  </div>
              </div>

              <div className="p-8">
                  <div className="grid grid-cols-2 gap-8">
                      <div className="text-center p-4 bg-gray-50 rounded-xl border border-gray-100">
                          <p className="text-gray-500 text-sm font-bold uppercase tracking-wider mb-1">Precio Unitario</p>
                          <p className="text-4xl font-black text-slate-800">${p.price}</p>
                      </div>

                      <div className={`text-center p-4 rounded-xl border ${isLowStock ? 'bg-red-50 border-red-100' : 'bg-green-50 border-green-100'}`}>
                          <p className={`text-sm font-bold uppercase tracking-wider mb-1 ${isLowStock ? 'text-red-500' : 'text-green-600'}`}>
                              Stock Disponible
                          </p>
                          <div className="flex items-center justify-center gap-2">
                              {isLowStock && <AlertTriangle className="text-red-500" />}
                              <p className={`text-4xl font-black ${isLowStock ? 'text-red-600' : 'text-green-700'}`}>
                                  {p.stock}
                              </p>
                          </div>
                      </div>
                  </div>

                  <div className="mt-8 bg-slate-50 rounded-lg p-4 border border-slate-200 flex items-center gap-3">
                      <Barcode className="text-slate-400" />
                      <div className="flex-1">
                          <p className="text-xs text-slate-500 font-bold uppercase">IMEI / Identificador</p>
                          <p className="text-lg font-mono text-slate-700 font-medium tracking-wide">{p.sku}</p>
                      </div>
                  </div>
              </div>
          </div>
      );
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 h-full flex flex-col">
        {/* Header Compacto */}
        <div className="text-center space-y-2">
            <h1 className="text-3xl font-bold text-slate-800">Verificador de Precios e Inventario</h1>
            <p className="text-slate-500">Escanea el código del producto para consultar su estatus.</p>
        </div>

        {/* Barra de Escaneo Gigante */}
        <div className="relative max-w-2xl mx-auto w-full group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                <Barcode className="h-6 w-6 text-blue-500 group-focus-within:text-blue-600 transition-colors" />
            </div>
            <input
                ref={inputRef}
                type="text"
                className="block w-full pl-12 pr-4 py-4 text-xl border-2 border-slate-200 rounded-2xl leading-5 bg-white placeholder-slate-400 focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-100 transition-all shadow-sm font-medium"
                placeholder="ESCANEA EL CÓDIGO AQUÍ..."
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                onKeyDown={handleScan}
                autoFocus
                autoComplete="off"
            />
            <div className="absolute inset-y-0 right-0 pr-4 flex items-center pointer-events-none">
               <span className="text-xs font-bold text-slate-300 border border-slate-200 px-2 py-1 rounded bg-slate-50">ENTER</span>
            </div>
        </div>

        {/* Área de Resultados */}
        <div className="flex-1 flex flex-col md:flex-row gap-6">

            {/* Tarjeta Principal */}
            <div className="flex-1">
                {renderResultCard()}
            </div>

            {/* Historial de Sesión (Sidebar) */}
            <div className="w-full md:w-80 bg-white rounded-2xl border border-gray-200 shadow-sm flex flex-col overflow-hidden max-h-[500px]">
                <div className="p-4 bg-gray-50 border-b border-gray-100 flex justify-between items-center">
                    <div className="flex items-center gap-2">
                        <History size={16} className="text-gray-500" />
                        <span className="text-sm font-bold text-gray-600">Historial Reciente</span>
                    </div>
                    {sessionHistory.length > 0 && (
                        <button onClick={clearSession} className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 font-medium">
                            <Trash2 size={12} /> Limpiar
                        </button>
                    )}
                </div>

                <div className="flex-1 overflow-y-auto p-2 space-y-2 custom-scrollbar">
                    {sessionHistory.length === 0 ? (
                        <div className="text-center py-8 text-gray-400 text-xs">
                            No hay escaneos recientes
                        </div>
                    ) : (
                        sessionHistory.map((item, idx) => (
                            <div key={idx} className={`p-3 rounded-xl border flex items-center justify-between animate-in slide-in-from-left-2 duration-200 ${item.status === 'found' ? 'bg-white border-gray-100' : 'bg-red-50 border-red-100'}`}>
                                <div className="overflow-hidden">
                                    <p className={`text-sm font-bold truncate ${item.status === 'found' ? 'text-gray-800' : 'text-red-600'}`}>
                                        {item.status === 'found' ? item.product?.name : 'Desconocido'}
                                    </p>
                                    <p className="text-[10px] text-gray-500 font-mono">{item.sku}</p>
                                </div>
                                <div className="text-right shrink-0">
                                    {item.status === 'found' ? (
                                        <>
                                            <p className="text-xs font-bold text-blue-600">${item.product?.price}</p>
                                            <p className="text-[10px] text-gray-400">{new Date(item.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit', second:'2-digit'})}</p>
                                        </>
                                    ) : (
                                        <AlertTriangle size={16} className="text-red-400" />
                                    )}
                                </div>
                            </div>
                        ))
                    )}
                </div>

                {sessionHistory.length > 0 && (
                    <div className="p-3 bg-gray-50 border-t border-gray-100 text-center text-xs text-gray-500">
                        {sessionHistory.length} ítems escaneados
                    </div>
                )}
            </div>
        </div>
    </div>
  );
};

export default InventoryView;

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  ShoppingCart, 
  Package, 
  RotateCcw, 
  Grid, 
  Menu, 
  X, 
  LogOut, 
  Users,
  UserCircle,
  Loader2,
  RefreshCw,
  WifiOff
} from 'lucide-react';
import { Product, Sale, Purchase, ViewState, ExternalApp, Customer, User } from './types';
import Dashboard from './components/Dashboard';
import AppLauncher from './components/AppLauncher';
import ChatBot from './components/ChatBot';
import Login from './components/Login';
import UsersView from './components/UsersView';
import CustomersView from './components/CustomersView';
import SalesView from './components/SalesView';
import PurchasesView from './components/PurchasesView';
import InventoryView from './components/InventoryView';
import { fetchAllData, api } from './services/api';

// -- INLINE COMPONENTS --
const ReturnsView = () => (
    <div className="bg-white p-8 rounded-xl shadow-sm border border-gray-200 text-center">
        <RotateCcw className="w-16 h-16 text-orange-400 mx-auto mb-4" />
        <h2 className="text-2xl font-bold text-gray-800 mb-2">Gestión de Devoluciones</h2>
        <p className="text-gray-500 max-w-md mx-auto mb-6">Escanea el ticket de venta para iniciar garantía.</p>
    </div>
);

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);

  // Data State
  const [products, setProducts] = useState<Product[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [apps, setApps] = useState<ExternalApp[]>([]);

  // Initial Data Load
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setIsSyncing(true);
    try {
        const data = await fetchAllData();

        if (data) {
             setProducts(data.products || []);
             setSales(data.sales || []);
             setCustomers(data.customers || []);
             setUsers(data.users || []);
             setApps(data.apps || []);
        }
    } catch (e) {
        console.error("Error crítico cargando datos", e);
    } finally {
        setIsLoading(false);
        setIsSyncing(false);
    }
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    if (user.role === 'warehouse') setCurrentView('inventory');
    else if (user.role === 'seller') setCurrentView('sales');
    else setCurrentView('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  // --- LOGICA PRINCIPAL DE VENTA ---
  const handleNewSale = async (sale: Sale, customer?: Customer) => {
    console.log("🚀 Procesando Venta:", sale.id);

    // 1. ACTUALIZACIÓN OPTIMISTA (UI INSTANTÁNEA)
    const updatedProducts = products.map(p => {
        const itemSold = sale.items.find(i => i.productId === p.id);
        if (itemSold) {
            const currentStock = typeof p.stock === 'number' ? p.stock : 0;
            return { ...p, stock: Math.max(0, currentStock - itemSold.quantity) };
        }
        return p;
    });

    setProducts(updatedProducts);
    setSales(prev => [...prev, sale]);

    // Si hay cliente nuevo, lo agregamos localmente
    if (customer && customer.id) {
         if (!customers.find(c => c.id === customer.id)) {
             setCustomers(prev => [...prev, customer]);
         }
    }

    // 2. SINCRONIZACIÓN BACKGROUND (NO BLOQUEANTE)

    // a. Registrar Venta
    api.createSale(sale).catch(e => console.error("Error sync venta", e));

    // b. Registrar Cliente
    if (customer) {
        api.createCustomer(customer).catch(e => console.error("Error sync cliente", e));
    }

    // c. Actualizar Stock en Nube
    sale.items.forEach(item => {
        const p = updatedProducts.find(prod => prod.id === item.productId);
        if (p) {
             api.updateStock(p.id, p.stock).catch(e => console.error("Error stock sync", e));
        }
    });
  };

  const handlePurchase = async (purchase: Purchase) => {
      // 1. Optimistic Stock Update
      const updatedProducts = [...products];
      purchase.items.forEach(item => {
          const idx = updatedProducts.findIndex(p => p.id === item.productId);
          if (idx >= 0) {
              const currentStock = updatedProducts[idx].stock || 0;
              const newStock = currentStock + item.quantity;
              updatedProducts[idx] = { ...updatedProducts[idx], stock: newStock };

              // Sync Stock
              api.updateStock(updatedProducts[idx].id, newStock).catch(console.error);
          } else {
              // Create temp product if not exists
              // (In real app, we should probably force product creation first, but here we can add it)
              const newProduct: Product = {
                  id: item.productId,
                  name: item.name,
                  price: item.cost * 1.3, // Dummy markup
                  stock: item.quantity,
                  sku: 'N/A', // Not provided in purchase items directly unless mapped
                  category: 'General'
              };
              updatedProducts.push(newProduct);
          }
      });
      setProducts(updatedProducts);

      // 2. Sync Purchase
      api.createPurchase(purchase).catch(console.error);
  };

  const handleUpdateStock = async (id: string, newStock: number) => {
      setProducts(prev => prev.map(p => p.id === id ? { ...p, stock: newStock } : p));
      api.updateStock(id, newStock).catch(console.error);
  };

  const handleAddCustomer = (customer: Customer) => {
      setCustomers(prev => [...prev, customer]);
      api.createCustomer(customer).catch(console.error);
  };

  const handleAddUser = (user: User) => {
      setUsers(prev => [...prev, user]);
      api.createUser(user).catch(console.error);
  };

  const handleAddApp = (app: ExternalApp) => {
      setApps(prev => [...prev, app]);
      api.createApp(app).catch(console.error);
  };

  const handleRemoveApp = (id: string) => {
      setApps(prev => prev.filter(a => a.id !== id));
      api.deleteApp(id).catch(console.error);
  };

  // --- RENDERING ---

  if (isLoading) {
      return (
          <div className="h-screen flex items-center justify-center bg-gray-50 flex-col gap-4">
              <Loader2 className="animate-spin text-blue-600 w-10 h-10" />
              <p className="text-gray-500 font-medium">Cargando Sistema...</p>
          </div>
      );
  }

  if (!currentUser) {
      return <Login onLogin={handleLogin} users={users} />;
  }

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard, roles: ['admin'] },
    { id: 'sales', label: 'Ventas', icon: ShoppingCart, roles: ['admin', 'seller'] },
    { id: 'purchases', label: 'Compras', icon: Package, roles: ['admin', 'warehouse'] },
    { id: 'inventory', label: 'Inventario', icon: Grid, roles: ['admin', 'warehouse'] },
    { id: 'returns', label: 'Devoluciones', icon: RotateCcw, roles: ['admin', 'seller'] },
    { id: 'customers', label: 'Clientes', icon: Users, roles: ['admin', 'seller'] },
    { id: 'users', label: 'Usuarios', icon: UserCircle, roles: ['admin'] },
    { id: 'apps', label: 'Aplicaciones', icon: Grid, roles: ['admin', 'seller', 'warehouse'] },
  ];

  const filteredMenu = menuItems.filter(item => item.roles.includes(currentUser.role));

  const renderContent = () => {
      switch (currentView) {
          case 'dashboard': return <Dashboard sales={sales} />;
          case 'sales': return <SalesView products={products} customers={customers} onSale={handleNewSale} />;
          case 'purchases': return <PurchasesView onPurchase={handlePurchase} />;
          case 'inventory': return <InventoryView products={products} onUpdateStock={handleUpdateStock} />;
          case 'customers': return <CustomersView customers={customers} onAddCustomer={handleAddCustomer} />;
          case 'users': return <UsersView users={users} onAddUser={handleAddUser} />;
          case 'apps': return <AppLauncher apps={apps} onAddApp={handleAddApp} onRemoveApp={handleRemoveApp} />;
          case 'returns': return <ReturnsView />;
          default: return <Dashboard sales={sales} />;
      }
  };

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden font-sans">
        {/* SIDEBAR */}
        <aside className={`${sidebarOpen ? 'w-64' : 'w-20'} bg-slate-900 text-white transition-all duration-300 flex flex-col shadow-xl z-20`}>
            <div className="p-4 flex items-center justify-between border-b border-slate-800">
                {sidebarOpen && <h1 className="font-bold text-xl tracking-tight bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent">SistemCaja</h1>}
                <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 hover:bg-slate-800 rounded-lg transition-colors">
                    {sidebarOpen ? <X size={20} /> : <Menu size={20} />}
                </button>
            </div>

            <nav className="flex-1 py-6 px-3 space-y-2 overflow-y-auto custom-scrollbar">
                {filteredMenu.map(item => (
                    <button
                        key={item.id}
                        onClick={() => setCurrentView(item.id as ViewState)}
                        className={`w-full flex items-center gap-3 p-3 rounded-xl transition-all duration-200 group ${
                            currentView === item.id 
                            ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' 
                            : 'text-slate-400 hover:bg-slate-800 hover:text-white'
                        }`}
                    >
                        <item.icon size={22} className={`${currentView === item.id ? 'animate-pulse' : ''}`} />
                        {sidebarOpen && <span className="font-medium">{item.label}</span>}

                        {!sidebarOpen && (
                            <div className="absolute left-16 bg-slate-800 text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-50">
                                {item.label}
                            </div>
                        )}
                    </button>
                ))}
            </nav>

            <div className="p-4 border-t border-slate-800">
                <div className={`flex items-center gap-3 ${!sidebarOpen && 'justify-center'}`}>
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-purple-500 to-pink-500 flex items-center justify-center text-white font-bold text-sm shrink-0">
                        {currentUser.username.substring(0,2).toUpperCase()}
                    </div>
                    {sidebarOpen && (
                        <div className="overflow-hidden">
                            <p className="text-sm font-bold truncate">{currentUser.name}</p>
                            <p className="text-xs text-slate-500 capitalize">{currentUser.role}</p>
                        </div>
                    )}
                </div>
                <button 
                    onClick={handleLogout}
                    className={`mt-4 w-full flex items-center justify-center gap-2 p-2 rounded-lg text-red-400 hover:bg-red-500/10 hover:text-red-300 transition-colors ${!sidebarOpen && 'mt-6'}`}
                >
                    <LogOut size={18} />
                    {sidebarOpen && <span className="text-sm font-medium">Cerrar Sesión</span>}
                </button>
            </div>
        </aside>

        {/* MAIN CONTENT */}
        <main className="flex-1 flex flex-col relative overflow-hidden">
            {/* Top Bar for Sync Status */}
            <div className="bg-white border-b border-gray-200 px-6 py-2 flex justify-between items-center h-14 shrink-0">
                <div className="flex items-center gap-2 text-sm text-gray-500">
                    {isSyncing ? (
                        <>
                            <Loader2 size={14} className="animate-spin text-blue-500" />
                            <span>Sincronizando...</span>
                        </>
                    ) : (
                        <>
                            <RefreshCw size={14} className="text-green-500" />
                            <span>Sistema Actualizado</span>
                        </>
                    )}
                </div>
                {!isSyncing && !isLoading && products.length === 0 && (
                     <div className="flex items-center gap-2 text-xs text-red-500 bg-red-50 px-3 py-1 rounded-full">
                        <WifiOff size={12} />
                        Modo Offline / Sin Datos
                     </div>
                )}
            </div>

            <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar relative">
                {renderContent()}
            </div>

            <ChatBot />
        </main>
    </div>
  );
};

export default App;

